export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING'
}

export type FailureType = 'ELECTRICAL' | 'ELECTRONIC' | 'MECHANICAL' | 'LEAKAGE';
export type RollFailureType = 'ECATS' | 'VELOCITY';
export type QualityStatus = 'NONE' | 'PASS' | 'FAIL';
export type RollTestStep = 'READY' | 'ECATS' | 'ACCEL' | 'BRAKE' | 'DONE';

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; // Processing time in frames
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasEngine: boolean;
  hasWheels: boolean;
  hasFluids: boolean;
  hasDefect: boolean;
  isRepaired: boolean;
  inRepair: boolean;
  color: string;
  baseColor: string;
  finished: boolean;
  progress: number;
  everRepaired: boolean;
  ignoreCollisionTimer: number;
  pendingRepairs: number;
  completedRepairs: number;
  initialRepairs: number;
  isLocked: boolean;
  failureType: FailureType | null;
  lastFailureType: FailureType | null;
  workOrderId: string | null;
  repairStartTime: number | null;
  currentLeadTime: number;
  faiStatus: QualityStatus;
  waterTestStatus: QualityStatus;
  finalInspectionStatus: QualityStatus;
  everEnteredWaitingArea: boolean;
  waitingAreaEntryCount: number;
  isFtrNegative: boolean;
  // Quality Flow specific
  viaVerde: boolean;
  repairCycleCount: number;
  inRetest: boolean;
  // Roll Test specific
  rollTestStatus: QualityStatus;
  rollTestFailType: RollFailureType | null;
  assignedCabinId: string | null;
  rollStep: RollTestStep;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  cycleTime: number;
  totalStarted: number;
  passedFirstTime: number; // For FTT
  totalRepaired: number;
  repairAttempts: number;
  totalStagesCompleted: number;
  totalLeadTimeFrames: number;
  repairCompletedCount: number;
  ftrFails: number;
  ftrSuccesses: number;
  categoryVolumes: Record<FailureType, number>;
  totalWaitAreaEntries: number;
  // Roll Test specific
  rollTestProcessed: number;
  ecatsFailures: number;
  velocityFailures: number;
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  Cpu,
  CheckCircle2,
  ShieldAlert,
  MonitorDot,
  Search,
  ArrowRightCircle,
  Terminal,
  Key,
  Timer,
  BarChart,
  LayoutGrid,
  History,
  AlertCircle,
  ChevronRight,
  Gauge,
  Zap,
  ActivitySquare,
  Radio,
  Droplets,
  Activity
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, QualityStatus, RollFailureType, RollTestStep } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(420); // Faster to reach 500 VPD scale
  const [speed] = useState(3.2);
  const [defectRate] = useState(0.18); 
  const [scale, setScale] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, cycleTime: 0, totalStarted: 0, passedFirstTime: 0, 
    totalRepaired: 0, repairAttempts: 0, totalStagesCompleted: 0, totalLeadTimeFrames: 0, 
    repairCompletedCount: 0, ftrFails: 0, ftrSuccesses: 0, 
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0, rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);
  const mousePosRef = useRef<Point | null>(null);

  const updateScale = useCallback(() => {
    if (!containerRef.current) return;
    const { clientWidth, clientHeight } = containerRef.current;
    const s = Math.min((clientWidth - 40) / SIM_WIDTH, (clientHeight - 40) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColors = ['#e2e8f0', '#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasEngine: false, hasWheels: false, hasFluids: false, hasDefect: Math.random() < defectRate,
      isRepaired: false, inRepair: false, color: bodyColor, baseColor: bodyColor, finished: false, progress: 0,
      everRepaired: false, ignoreCollisionTimer: 0, pendingRepairs: 0, completedRepairs: 0, initialRepairs: 0,
      isLocked: false, failureType: null, lastFailureType: null, workOrderId: null, repairStartTime: null,
      currentLeadTime: 0, faiStatus: 'NONE', waterTestStatus: 'NONE', finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false, waitingAreaEntryCount: 0, isFtrNegative: false, viaVerde: true,
      repairCycleCount: 0, inRetest: false, rollTestStatus: 'NONE', rollTestFailType: null, assignedCabinId: null,
      rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; 
      v.waitingTimer = 0; 
      v.ignoreCollisionTimer = 60; 
      addLog(`UNIT ${v.id.toUpperCase()} VERIFIED & SYNCED`); 
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair && v.repairStartTime !== null) v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      // Update Roll Test Protocol Stages
      if (v.waitingTimer > 0) {
        v.waitingTimer--;

        const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
        if (cabin) {
            const totalWait = cabin.wait;
            const elapsed = totalWait - v.waitingTimer;
            if (elapsed < totalWait * 0.33) v.rollStep = 'ECATS';
            else if (elapsed < totalWait * 0.66) v.rollStep = 'ACCEL';
            else if (v.waitingTimer > 0) v.rollStep = 'BRAKE';
            else v.rollStep = 'DONE';
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);

      // Smart Buffer: Vehicles don't overlap, especially at merge points
      const hasBlocker = currentVehicles.some(o => {
          if (o.id === v.id) return false;
          const d = Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2));
          return d < 65 && o.pathIdx >= v.pathIdx;
      });
      if (v.ignoreCollisionTimer <= 0 && hasBlocker) continue;

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        // Cabin Gatekeeper: Strict 1-per-cabin Logic
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
            if (availableIdx !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0;
                addLog(`${v.id.toUpperCase()} ENTERING CABIN ${availableIdx + 1}`);
            } else { v.pathIdx--; continue; } // Block if no cabin free
        }

        // Clean up cabin assignment at merge
        if (v.assignedCabinId && v.pos.x === MAIN_PATH_POINTS[MERGE_POINT_IDX].x && v.pos.y === MAIN_PATH_POINTS[MERGE_POINT_IDX].y) {
            v.assignedCabinId = null;
            v.rollStep = 'READY';
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const routeToRepair = (source: string, type: FailureType) => {
            v.viaVerde = false; 
            v.inRepair = true; 
            v.failureType = type; 
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS]; 
            v.pathIdx = 0; 
            v.color = COLORS.REPAIR;
            setStats(s => ({ 
              ...s, 
              defects: s.defects + 1, 
              categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } 
            }));
            addLog(`${v.id.toUpperCase()}: ${source} FAILED [${type}]`);
          };

          // Roll Test Logic with 500 VPD scale
          if (station.name.startsWith('Teste Rolo')) {
             const isDefective = v.hasDefect && Math.random() < 0.4;
             if (isDefective) {
                const rollFailType: RollFailureType = Math.random() < 0.6 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL'; 
                v.rollTestFailType = rollFailType;
                if (rollFailType === 'ECATS') { 
                  setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 })); 
                  routeToRepair('ROLL (ECATS)', 'ELECTRONIC'); 
                } else { 
                  setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 })); 
                  routeToRepair('ROLL (ACCEL)', 'MECHANICAL'); 
                }
             } else { 
               v.rollTestStatus = 'PASS'; 
               setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); 
               addLog(`ROLL PASS: ${v.id.toUpperCase()} - ALL SYSTEMS OK`); 
             }
          }

          // Water Test Integration
          if (station.name === 'SISTEMA ÁGUA') {
            if (v.rollTestStatus !== 'PASS' && !v.inRepair) {
              // Should not happen with current routing but for safety
              routeToRepair('BYPASS PREVENTED', 'MECHANICAL');
            } else if (Math.random() < 0.08) {
              v.waterTestStatus = 'FAIL'; 
              routeToRepair('WATER LEAK', 'LEAKAGE');
            } else {
              v.waterTestStatus = 'PASS';
              addLog(`${v.id.toUpperCase()} WATER TEST: PASS`);
            }
          }

          // Repair Return Integration
          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false; v.color = v.baseColor;
            setStats(s => ({ ...s, repairCompletedCount: s.repairCompletedCount + 1, ftrSuccesses: s.ftrSuccesses + 1 }));

            // Retest logic based on failure type
            if (v.failureType === 'LEAKAGE') { 
                v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; addLog(`REPAIR DONE: ${v.id.toUpperCase()} -> WATER RE-VALIDATION`);
            } else { 
                v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 10; addLog(`REPAIR DONE: ${v.id.toUpperCase()} -> FULL RE-TEST`);
            }
          }
        }
      } else { const r = speed / dist; v.pos.x += dx * r; v.pos.y += dy * r; }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid pattern
    ctx.strokeStyle = '#0f172a'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const line = (pts: Point[], col = COLORS.CONVEYOR, w = 24) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    // Draw Paths
    line(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), '#1e293b', 28);
    ROLL_TEST_BRANCHES.forEach(b => line(b, '#0f172a', 32));
    line(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX), '#1e293b', 28);
    line(REPAIR_PATH_POINTS, '#180a0a', 32);

    // Draw Stations / Cabins
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRollTest = s.name.startsWith('Teste Rolo');
      const w = s.width || (isRollTest ? 140 : 100), h = s.height || (isRollTest ? 60 : 38), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status = vehicleIn ? (vehicleIn.waitingTimer > 0 ? 'PROCESSING' : 'OCCUPIED') : 'IDLE';

      // Base
      ctx.fillStyle = isRollTest ? '#020617' : '#0f172a'; 
      ctx.strokeStyle = isRollTest ? (status === 'PROCESSING' ? '#6366f1' : '#334155') : 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 8); ctx.fill(); ctx.stroke();

      // Label
      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#f59e0b' : '#334155');
      ctx.beginPath(); ctx.arc(x + 16, y + (isRollTest ? 15 : h / 2), 5, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#94a3b8'; ctx.font = `600 ${isRollTest ? '10px' : '8px'} Inter`; 
      ctx.fillText(s.name.toUpperCase(), x + 28, y + (isRollTest ? 18 : h / 2 + 3));

      // Roll Test Protocol Details
      if (isRollTest && vehicleIn) {
        ctx.fillStyle = '#1e293b'; ctx.beginPath(); ctx.roundRect(x + 10, y + 35, w - 20, 15, 4); ctx.fill();
        ctx.fillStyle = '#6366f1'; ctx.font = 'bold 8px Inter';
        ctx.fillText(`PROT: ${vehicleIn.rollStep}`, x + 15, y + 46);
        // Progress bar inside cabin
        const prog = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = '#10b981'; ctx.beginPath(); ctx.roundRect(x + 10, y + 52, (w - 20) * prog, 2, 1); ctx.fill();
      }
    });

    // Draw Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      // Telemetry Bubble for Roll Testing Vehicles
      if (v.assignedCabinId && v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(0,0,0,0.8)'; ctx.beginPath(); ctx.roundRect(v.pos.x - 40, v.pos.y - 45, 80, 20, 4); ctx.fill();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 8px Inter';
        ctx.textAlign = 'center';
        ctx.fillText(`${v.rollStep} @ ${Math.floor(Math.random()*120)}KM/H`, v.pos.x, v.pos.y - 32);
        ctx.textAlign = 'start';
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const cabins = [0, 1, 2].map(i => vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id));

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">
      <aside className="w-[380px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-20">
        <div className="p-8 border-b border-slate-900/50 space-y-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-500/10 rounded-lg"><Activity className="w-5 h-5 text-indigo-500" /></div>
              <h1 className="text-xs font-bold tracking-widest text-slate-200 uppercase">Roll Master 5.0</h1>
            </div>
            <div className={`flex items-center gap-1.5 text-[9px] font-bold uppercase ${isRunning ? 'text-emerald-500' : 'text-rose-500'}`}>
               <Radio className={`w-3 h-3 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Live Telemetry' : 'System Halted'}
            </div>
          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-baseline">
              <span className="text-[10px] font-semibold text-slate-600 uppercase tracking-wider">Flow Efficiency (500 VPD)</span>
              <span className="text-xl font-bold text-slate-100 tabular-nums">{stats.produced} <span className="text-slate-800">/ 500</span></span>
            </div>
            <div className="h-2 w-full bg-slate-950 rounded-full overflow-hidden border border-slate-900">
               <div className="h-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.5)] transition-all duration-700" style={{ width: `${(stats.produced / 500) * 100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/20 px-4 border-b border-slate-900/50">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" /> },
            { id: 'QUALITY', icon: <ShieldAlert className="w-4 h-4" /> },
            { id: 'NODES', icon: <LayoutGrid className="w-4 h-4" /> }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as DashboardTab)} className={`flex-1 flex justify-center py-5 transition-all relative ${activeTab === tab.id ? 'text-indigo-400' : 'text-slate-600 hover:text-slate-400'}`}>
              {tab.icon}
              {activeTab === tab.id && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-500" />}
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-8 space-y-10">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <section className="space-y-4">
                <header className="text-[10px] font-bold text-slate-600 uppercase tracking-[0.2em] flex items-center gap-2"><ActivitySquare className="w-3.5 h-3.5" /> Cabin Occupancy</header>
                <div className="grid grid-cols-3 gap-3">
                  {cabins.map((v, i) => (
                    <div key={i} className={`p-4 rounded-xl border flex flex-col items-center gap-2 transition-all ${v ? 'bg-indigo-500/5 border-indigo-500/30 shadow-lg' : 'bg-slate-900/20 border-slate-900'}`}>
                      <Gauge className={`w-5 h-5 ${v ? 'text-indigo-400' : 'text-slate-800'}`} />
                      <div className="flex flex-col items-center">
                        <span className={`text-[9px] font-bold uppercase tracking-tighter ${v ? 'text-indigo-400' : 'text-slate-800'}`}>{v ? 'Testing' : 'Idle'}</span>
                        {v && <span className="text-[8px] text-slate-500 font-mono">#{v.id.toUpperCase()}</span>}
                      </div>
                    </div>
                  ))}
                </div>
              </section>

              <section className="grid grid-cols-2 gap-4">
                <div className="p-5 bg-slate-900/30 border border-slate-900 rounded-2xl space-y-1 group hover:border-emerald-500/20 transition-colors">
                  <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">FTT Quality</span>
                  <div className="text-2xl font-bold text-emerald-400">{fttRate.toFixed(1)}%</div>
                  <div className="text-[8px] text-slate-700">First-Time-Through</div>
                </div>
                <div className="p-5 bg-slate-900/30 border border-slate-900 rounded-2xl space-y-1 group hover:border-indigo-500/20 transition-colors">
                  <span className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">FTR Index</span>
                  <div className="text-2xl font-bold text-indigo-400">{ftrRate.toFixed(1)}%</div>
                  <div className="text-[8px] text-slate-700">Final-Through-Repair</div>
                </div>
              </section>

              <section className="space-y-5 bg-slate-900/10 p-5 rounded-2xl border border-slate-900/50">
                <header className="flex justify-between items-center text-[10px] font-bold text-slate-600 uppercase tracking-[0.2em]"><span>Roll Failure Analysis</span> <Zap className="w-3.5 h-3.5" /></header>
                <div className="space-y-6">
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold uppercase tracking-tight">
                      <span className="text-slate-500 flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-indigo-500" /> ECATS (Digital/Elec)</span>
                      <span className="text-slate-300">{stats.ecatsFailures}</span>
                    </div>
                    <div className="h-1.5 w-full bg-slate-950 rounded-full overflow-hidden border border-slate-900">
                      <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${(stats.ecatsFailures / (stats.ecatsFailures + stats.velocityFailures || 1)) * 100}%` }} />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[10px] font-bold uppercase tracking-tight">
                      <span className="text-slate-500 flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-amber-500" /> VELOCITY (0-100)</span>
                      <span className="text-slate-300">{stats.velocityFailures}</span>
                    </div>
                    <div className="h-1.5 w-full bg-slate-950 rounded-full overflow-hidden border border-slate-900">
                      <div className="h-full bg-amber-500 transition-all duration-1000" style={{ width: `${(stats.velocityFailures / (stats.ecatsFailures + stats.velocityFailures || 1)) * 100}%` }} />
                    </div>
                  </div>
                </div>
              </section>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="space-y-6 animate-in fade-in duration-500">
               <header className="flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-600">
                 <span>Resolution Waiting Area</span>
                 <span className="px-2 py-1 bg-rose-500/10 border border-rose-500/20 text-rose-500 rounded text-[9px]">{vehiclesRef.current.filter(v=>v.inRepair).length} PENDING</span>
               </header>
               <div className="space-y-4">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="p-6 bg-slate-900/40 border border-slate-900 rounded-2xl space-y-5 group hover:border-indigo-500/30 transition-all">
                       <div className="flex justify-between items-center">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-5 rounded border border-slate-800 shadow-lg" style={{ backgroundColor: v.color }} />
                            <span className="text-xs font-bold text-slate-200 tracking-wider">UNIT-{v.id.toUpperCase()}</span>
                          </div>
                          <span className="text-[10px] font-mono text-slate-600 tabular-nums">{((v.currentLeadTime||0)/60).toFixed(0)}s</span>
                       </div>
                       <div className="flex justify-between text-[9px] font-bold text-slate-500 uppercase">
                         <span className="flex items-center gap-1.5 text-rose-500/80"><AlertCircle className="w-3 h-3" /> {v.failureType}</span>
                         <span className="text-slate-800 font-mono">{v.workOrderId}</span>
                       </div>
                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-4 bg-indigo-600/10 hover:bg-indigo-600 text-indigo-500 hover:text-white border border-indigo-500/20 rounded-xl text-[10px] font-bold uppercase tracking-widest transition-all shadow-lg active:scale-95">Verify & Release to Flow</button>
                    </div>
                  ))}
                  {vehiclesRef.current.filter(v=>v.inRepair).length === 0 && (
                    <div className="py-24 flex flex-col items-center justify-center opacity-10">
                      <CheckCircle2 className="w-16 h-16 mb-4 text-emerald-500" />
                      <span className="text-xs font-bold uppercase tracking-[0.5em]">Sync Complete</span>
                    </div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'NODES' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700" />
                <input type="text" placeholder="Search factory nodes..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-900/20 border border-slate-900 rounded-xl py-4 pl-12 pr-4 text-[11px] font-medium focus:outline-none focus:border-indigo-500/40 transition-all placeholder:text-slate-800" />
              </div>
              <div className="grid grid-cols-1 gap-2">
                {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                  <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`p-4 rounded-xl border flex items-center justify-between transition-all cursor-default ${hoveredStationId === s.id ? 'bg-indigo-500/5 border-indigo-500/20' : 'bg-transparent border-transparent hover:bg-slate-900/20'}`}>
                     <div className="flex items-center gap-4">
                       <div className={`w-2 h-2 rounded-full ${s.type === 'TEST' ? 'bg-indigo-500' : 'bg-slate-800'}`} />
                       <span className={`text-[11px] font-bold transition-colors ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-400'}`}>{s.name}</span>
                     </div>
                     <span className="text-[8px] font-bold text-slate-800 uppercase tracking-widest px-2 py-0.5 border border-slate-800 rounded">{s.type}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="p-8 border-t border-slate-900/50 space-y-5 bg-slate-950/20">
           <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 120; }); addLog("MANUAL OVERRIDE: ALL UNITS SYNCED"); }} className="w-full py-4 bg-slate-900/50 border border-slate-900 hover:border-indigo-500/40 text-slate-500 hover:text-indigo-400 rounded-2xl text-[10px] font-bold uppercase tracking-[0.2em] transition-all flex justify-center gap-3 items-center active:scale-95"><Key className="w-4 h-4" /> Global Force-Sync</button>
           <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-4 rounded-2xl text-[10px] font-bold uppercase transition-all flex justify-center gap-2 items-center ${isRunning ? 'bg-slate-900 text-slate-600' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-900/40'}`}>
                 {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />} {isRunning ? 'Stop Line' : 'Start Line'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0,rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); addLog("KPI BUFFER RESET: NEW CYCLE"); }} className="py-4 bg-slate-900 text-slate-700 hover:text-rose-500 rounded-2xl text-[10px] font-bold uppercase transition-all flex justify-center gap-2 items-center border border-transparent hover:border-rose-900/30"><RotateCcw className="w-4 h-4" /> Reset</button>
           </div>
        </div>
      </aside>

      <main className="flex-1 relative flex flex-col bg-[#070b14]" ref={containerRef}>
        <div className="flex-1 flex items-center justify-center relative p-10">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center', transition: 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)' }} className="relative bg-[#020617] rounded-[2.5rem] shrink-0 overflow-hidden border border-slate-900 shadow-[0_0_100px_rgba(0,0,0,0.5)]">

            {/* Factory Overlays */}
            <div className="absolute top-12 left-12 flex flex-col gap-1 z-10 pointer-events-none">
                <span className="text-[10px] font-black text-slate-800 tracking-[0.5em] uppercase">Assembly_Line_Alpha</span>
                <div className="h-0.5 w-24 bg-slate-800" />
            </div>

            <div className="absolute bottom-12 right-12 flex gap-10 z-10 opacity-30 pointer-events-none">
                <div className="flex items-center gap-4 bg-slate-950/50 p-4 rounded-2xl border border-slate-900">
                  <Gauge className="w-10 h-10 text-indigo-500" />
                  <div className="flex flex-col">
                    <span className="text-xl font-black text-slate-200">0-100 VALID</span>
                    <span className="text-[8px] font-bold text-slate-600">CERTIFIED CALIBRATION</span>
                  </div>
                </div>
            </div>

            <canvas ref={canvasRef} width={SIM_WIDTH} height={SIM_HEIGHT} onMouseMove={(e) => {
              const r = canvasRef.current?.getBoundingClientRect();
              if (r) mousePosRef.current = { x: (e.clientX - r.left) / scale, y: (e.clientY - r.top) / scale };
            }} />
          </div>
        </div>

        {/* Footer Log */}
        <div className="h-16 bg-[#020617] border-t border-slate-900/50 flex items-center px-10 gap-10 shrink-0 overflow-hidden text-[10px] font-bold uppercase tracking-[0.3em] text-slate-700">
          <div className="flex items-center gap-3 text-indigo-500/70 shrink-0"><Terminal className="w-4 h-4" /> SYSTEM_TERMINAL</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center border-l border-slate-900 pl-10">
            <div className="flex gap-20 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-3 items-center ${l.includes('FAILED') || l.includes('LEAK') ? 'text-rose-600' : 'text-slate-500'}`}><div className={`w-1.5 h-1.5 rounded-full ${l.includes('FAILED') || l.includes('LEAK') ? 'bg-rose-600 animate-pulse' : 'bg-slate-800'}`} /> {l}</span>
              ))}
              {logs.length === 0 && <span className="opacity-30 italic">Synchronizing with Industrial IoT Mesh...</span>}
            </div>
          </div>
        </div>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 60s linear infinite; }
        .animate-in { animation: animateIn 0.8s ease-out; }
        @keyframes animateIn { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  CheckCircle2,
  ShieldAlert,
  Search,
  Terminal,
  Key,
  BarChart,
  LayoutGrid,
  AlertCircle,
  Gauge,
  Zap,
  ActivitySquare,
  Radio,
  Activity,
  Cpu,
  Boxes
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(420);
  const [speed] = useState(3.2);
  const [defectRate] = useState(0.18); 
  const [scale, setScale] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, cycleTime: 0, totalStarted: 0, passedFirstTime: 0, 
    totalRepaired: 0, repairAttempts: 0, totalStagesCompleted: 0, totalLeadTimeFrames: 0, 
    repairCompletedCount: 0, ftrFails: 0, ftrSuccesses: 0, 
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0, rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  // High DPI Scaling and Layout adjustment
  const updateScale = useCallback(() => {
    if (!containerRef.current || !canvasRef.current) return;
    const { clientWidth, clientHeight } = containerRef.current;

    // Calculate scale to fit with margin
    const padding = 60;
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));

    // Handle HiDPI Canvas
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) ctx.scale(dpr, dpr);
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    updateScale();
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasEngine: false, hasWheels: false, hasFluids: false, hasDefect: Math.random() < defectRate,
      isRepaired: false, inRepair: false, color: bodyColor, baseColor: bodyColor, finished: false, progress: 0,
      everRepaired: false, ignoreCollisionTimer: 0, pendingRepairs: 0, completedRepairs: 0, initialRepairs: 0,
      isLocked: false, failureType: null, lastFailureType: null, workOrderId: null, repairStartTime: null,
      currentLeadTime: 0, faiStatus: 'NONE', waterTestStatus: 'NONE', finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false, waitingAreaEntryCount: 0, isFtrNegative: false, viaVerde: true,
      repairCycleCount: 0, inRetest: false, rollTestStatus: 'NONE', rollTestFailType: null, assignedCabinId: null,
      rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; 
      v.waitingTimer = 0; 
      v.ignoreCollisionTimer = 60; 
      addLog(`UNIT ${v.id.toUpperCase()} VERIFIED & SYNCED`); 
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair && v.repairStartTime !== null) v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
        if (cabin) {
            const totalWait = cabin.wait;
            const elapsed = totalWait - v.waitingTimer;
            if (elapsed < totalWait * 0.33) v.rollStep = 'ECATS';
            else if (elapsed < totalWait * 0.66) v.rollStep = 'ACCEL';
            else if (v.waitingTimer > 0) v.rollStep = 'BRAKE';
            else v.rollStep = 'DONE';
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      const hasBlocker = currentVehicles.some(o => {
          if (o.id === v.id) return false;
          const d = Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2));
          return d < 65 && o.pathIdx >= v.pathIdx;
      });
      if (v.ignoreCollisionTimer <= 0 && hasBlocker) continue;

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
            if (availableIdx !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0;
            } else { v.pathIdx--; continue; }
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 2 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 2) {
            v.assignedCabinId = null;
            v.rollStep = 'READY';
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;
          const routeToRepair = (source: string, type: FailureType) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type; 
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`${v.id.toUpperCase()}: ${source} FAILED [${type}]`);
          };

          if (station.name.startsWith('Teste Rolo')) {
             const isDefective = v.hasDefect && Math.random() < 0.4;
             if (isDefective) {
                const rollFailType: RollFailureType = Math.random() < 0.6 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL'; v.rollTestFailType = rollFailType;
                if (rollFailType === 'ECATS') { setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 })); routeToRepair('ROLL (ECATS)', 'ELECTRONIC'); }
                else { setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 })); routeToRepair('ROLL (ACCEL)', 'MECHANICAL'); }
             } else { 
               v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); 
             }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.rollTestStatus !== 'PASS' && !v.inRepair) routeToRepair('BYPASS PREVENTED', 'MECHANICAL');
            else if (Math.random() < 0.08) { v.waterTestStatus = 'FAIL'; routeToRepair('WATER LEAK', 'LEAKAGE'); }
            else v.waterTestStatus = 'PASS';
          }

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false; v.color = v.baseColor;
            setStats(s => ({ ...s, repairCompletedCount: s.repairCompletedCount + 1, ftrSuccesses: s.ftrSuccesses + 1 }));
            if (v.failureType === 'LEAKAGE') { v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; }
            else { v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 10; }
          }
        }
      } else { const r = speed / dist; v.pos.x += dx * r; v.pos.y += dy * r; }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Industrial Grid (Subtle)
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=50) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=50) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const drawPath = (pts: Point[], col = 'rgba(30, 41, 59, 0.8)', w = 24) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
      // Tech-line detail
      ctx.beginPath(); ctx.strokeStyle = 'rgba(255,255,255,0.03)'; ctx.lineWidth = 2;
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    // Draw Factory Structures
    drawPath(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), '#1e293b', 30);
    ROLL_TEST_BRANCHES.forEach(b => drawPath(b, '#0f172a', 36));
    drawPath(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX), '#1e293b', 30);
    drawPath(REPAIR_PATH_POINTS, '#180a0a', 34);

    // Render Nodes
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRollTest = s.name.startsWith('Teste Rolo');
      const w = s.width || (isRollTest ? 140 : 100), h = s.height || (isRollTest ? 64 : 42), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status = vehicleIn ? (vehicleIn.waitingTimer > 0 ? 'PROCESSING' : 'OCCUPIED') : 'IDLE';

      // Node Shadow & Base
      ctx.shadowBlur = 10; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.fillStyle = isRollTest ? '#020617' : '#0f172a'; 
      ctx.strokeStyle = isRollTest ? (status === 'PROCESSING' ? '#6366f1' : '#1e293b') : 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      // Node Meta
      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#f59e0b' : '#334155');
      ctx.beginPath(); ctx.arc(x + 16, y + 14, 4, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#94a3b8'; ctx.font = `bold ${isRollTest ? '11px' : '9px'} Inter`; 
      ctx.fillText(s.name.toUpperCase(), x + 28, y + 18);

      // Roll Test Details
      if (isRollTest && vehicleIn) {
        ctx.fillStyle = 'rgba(99, 102, 241, 0.1)'; ctx.beginPath(); ctx.roundRect(x + 8, y + 32, w - 16, 22, 6); ctx.fill();
        ctx.fillStyle = '#6366f1'; ctx.font = '800 9px Inter';
        ctx.fillText(`${vehicleIn.rollStep}`, x + 16, y + 46);
        const prog = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(99, 102, 241, 0.2)'; ctx.fillRect(x + 50, y + 40, w - 70, 4);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 50, y + 40, (w - 70) * prog, 4);
      }
    });

    // Render Mobile Units
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      // Vehicle Glow
      ctx.shadowBlur = 8; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; 
      ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      if (v.assignedCabinId && v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(2, 6, 23, 0.9)'; ctx.beginPath(); ctx.roundRect(v.pos.x - 45, v.pos.y - 50, 90, 22, 6); ctx.fill();
        ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 1; ctx.stroke();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
        ctx.fillText(`${v.rollStep} RUNNING`, v.pos.x, v.pos.y - 36);
        ctx.textAlign = 'start';
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; 
    const loop = () => { 
      updateSimulation(); 
      if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); 
      fId = requestAnimationFrame(loop); 
    };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const cabins = [0, 1, 2].map(i => vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id));

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden selection:bg-indigo-500/30">

      {/* Sidebar: Control Center */}
      <aside className="w-[400px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="p-8 border-b border-slate-900/50 space-y-8 bg-gradient-to-b from-indigo-500/5 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-500 rounded-xl shadow-[0_0_20px_rgba(99,102,241,0.4)]">
