                <div className="text-sm font-bold text-indigo-400 tracking-tight">{((stats.produced / 500) * 100).toFixed(1)}%</div>
              </div>
            </div>
            <div className="h-2.5 w-full bg-slate-950 rounded-full overflow-hidden border border-slate-900 p-[2px]">
               <div className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.4)] transition-all duration-1000 ease-out" style={{ width: `${(stats.produced / 500) * 100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/40 p-1.5 mx-8 my-6 rounded-xl border border-slate-900/50">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" />, label: 'Analytics' },
            { id: 'QUALITY', icon: <ShieldAlert className="w-4 h-4" />, label: 'Repair' },
