import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  CheckCircle2,
  ShieldAlert,
  Search,
  Terminal,
  Key,
  BarChart,
  LayoutGrid,
  AlertCircle,
  Gauge,
  Zap,
  ActivitySquare,
  Radio,
  Activity,
  Cpu,
  Boxes
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(420);
  const [speed] = useState(3.2);
  const [defectRate] = useState(0.18); 
  const [scale, setScale] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, cycleTime: 0, totalStarted: 0, passedFirstTime: 0, 
    totalRepaired: 0, repairAttempts: 0, totalStagesCompleted: 0, totalLeadTimeFrames: 0, 
    repairCompletedCount: 0, ftrFails: 0, ftrSuccesses: 0, 
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0, rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  // High DPI Scaling and Centered Layout adjustment
  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const { clientWidth, clientHeight } = viewportRef.current;

    // Calculate scale based on the actual available viewport space
    const padding = 80; // More breathing room
    const s = Math.min((clientWidth - padding) / SIM_WIDTH, (clientHeight - padding) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));

    // Handle HiDPI Canvas
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.resetTransform();
      ctx.scale(dpr, dpr);
    }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    // Use an IntersectionObserver or a small timeout to ensure layout is ready
    const timer = setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => {
      window.removeEventListener('resize', updateScale);
      clearTimeout(timer);
    };
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasEngine: false, hasWheels: false, hasFluids: false, hasDefect: Math.random() < defectRate,
      isRepaired: false, inRepair: false, color: bodyColor, baseColor: bodyColor, finished: false, progress: 0,
      everRepaired: false, ignoreCollisionTimer: 0, pendingRepairs: 0, completedRepairs: 0, initialRepairs: 0,
      isLocked: false, failureType: null, lastFailureType: null, workOrderId: null, repairStartTime: null,
      currentLeadTime: 0, faiStatus: 'NONE', waterTestStatus: 'NONE', finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false, waitingAreaEntryCount: 0, isFtrNegative: false, viaVerde: true,
      repairCycleCount: 0, inRetest: false, rollTestStatus: 'NONE', rollTestFailType: null, assignedCabinId: null,
      rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; 
      v.waitingTimer = 0; 
      v.ignoreCollisionTimer = 60; 
      addLog(`UNIT ${v.id.toUpperCase()} VERIFIED & SYNCED`); 
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair && v.repairStartTime !== null) v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
        if (cabin) {
            const totalWait = cabin.wait;
            const elapsed = totalWait - v.waitingTimer;
            if (elapsed < totalWait * 0.33) v.rollStep = 'ECATS';
            else if (elapsed < totalWait * 0.66) v.rollStep = 'ACCEL';
            else if (v.waitingTimer > 0) v.rollStep = 'BRAKE';
            else v.rollStep = 'DONE';
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      const hasBlocker = currentVehicles.some(o => {
          if (o.id === v.id) return false;
          const d = Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2));
          return d < 65 && o.pathIdx >= v.pathIdx;
      });
      if (v.ignoreCollisionTimer <= 0 && hasBlocker) continue;

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
            if (availableIdx !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0;
            } else { v.pathIdx--; continue; }
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 2 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 2) {
            v.assignedCabinId = null;
            v.rollStep = 'READY';
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;
          const routeToRepair = (source: string, type: FailureType) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type; 
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`${v.id.toUpperCase()}: ${source} FAILED [${type}]`);
          };

          if (station.name.startsWith('Teste Rolo')) {
             const isDefective = v.hasDefect && Math.random() < 0.4;
             if (isDefective) {
                const rollFailType: RollFailureType = Math.random() < 0.6 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL'; v.rollTestFailType = rollFailType;
                if (rollFailType === 'ECATS') { setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 })); routeToRepair('ROLL (ECATS)', 'ELECTRONIC'); }
                else { setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 })); routeToRepair('ROLL (ACCEL)', 'MECHANICAL'); }
             } else { 
               v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); 
             }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.rollTestStatus !== 'PASS' && !v.inRepair) routeToRepair('BYPASS PREVENTED', 'MECHANICAL');
            else if (Math.random() < 0.08) { v.waterTestStatus = 'FAIL'; routeToRepair('WATER LEAK', 'LEAKAGE'); }
            else v.waterTestStatus = 'PASS';
          }

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false; v.color = v.baseColor;
            setStats(s => ({ ...s, repairCompletedCount: s.repairCompletedCount + 1, ftrSuccesses: s.ftrSuccesses + 1 }));
            if (v.failureType === 'LEAKAGE') { v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; }
            else { v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 10; }
          }
        }
      } else { const r = speed / dist; v.pos.x += dx * r; v.pos.y += dy * r; }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Industrial Grid (Subtle)
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=50) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=50) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const drawPath = (pts: Point[], col = 'rgba(30, 41, 59, 0.8)', w = 24) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
      ctx.beginPath(); ctx.strokeStyle = 'rgba(255,255,255,0.03)'; ctx.lineWidth = 2;
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    drawPath(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), '#1e293b', 30);
    ROLL_TEST_BRANCHES.forEach(b => drawPath(b, '#0f172a', 36));
    drawPath(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX), '#1e293b', 30);
    drawPath(REPAIR_PATH_POINTS, '#180a0a', 34);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRollTest = s.name.startsWith('Teste Rolo');
      const w = s.width || (isRollTest ? 140 : 100), h = s.height || (isRollTest ? 64 : 42), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status = vehicleIn ? (vehicleIn.waitingTimer > 0 ? 'PROCESSING' : 'OCCUPIED') : 'IDLE';

      ctx.shadowBlur = 10; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.fillStyle = isRollTest ? '#020617' : '#0f172a'; 
      ctx.strokeStyle = isRollTest ? (status === 'PROCESSING' ? '#6366f1' : '#1e293b') : 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#f59e0b' : '#334155');
      ctx.beginPath(); ctx.arc(x + 16, y + 14, 4, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#94a3b8'; ctx.font = `bold ${isRollTest ? '11px' : '9px'} Inter`; 
      ctx.fillText(s.name.toUpperCase(), x + 28, y + 18);

      if (isRollTest && vehicleIn) {
        ctx.fillStyle = 'rgba(99, 102, 241, 0.1)'; ctx.beginPath(); ctx.roundRect(x + 8, y + 32, w - 16, 22, 6); ctx.fill();
        ctx.fillStyle = '#6366f1'; ctx.font = '800 9px Inter';
        ctx.fillText(`${vehicleIn.rollStep}`, x + 16, y + 46);
        const prog = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(99, 102, 241, 0.2)'; ctx.fillRect(x + 50, y + 40, w - 70, 4);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 50, y + 40, (w - 70) * prog, 4);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 8; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; 
      ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      if (v.assignedCabinId && v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(2, 6, 23, 0.9)'; ctx.beginPath(); ctx.roundRect(v.pos.x - 45, v.pos.y - 50, 90, 22, 6); ctx.fill();
        ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 1; ctx.stroke();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
        ctx.fillText(`${v.rollStep} RUNNING`, v.pos.x, v.pos.y - 36);
        ctx.textAlign = 'start';
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; 
    const loop = () => { 
      updateSimulation(); 
      if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); 
      fId = requestAnimationFrame(loop); 
    };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const cabins = [0, 1, 2].map(i => vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id));

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden selection:bg-indigo-500/30">

      {/* Sidebar: Control Center */}
      <aside className="w-[400px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="p-8 border-b border-slate-900/50 space-y-8 bg-gradient-to-b from-indigo-500/5 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-500 rounded-xl shadow-[0_0_20px_rgba(99,102,241,0.4)]">
                <Boxes className="w-5 h-5 text-white" />
              </div>
              <div>
                <h1 className="text-[11px] font-black tracking-[0.3em] text-white uppercase">VPD SIMULATOR</h1>
                <p className="text-[9px] font-bold text-slate-500 tracking-wider">VERSION 5.2.0 RC</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[9px] font-black uppercase tracking-widest`}>
               <Radio className={`w-3 h-3 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Line Active' : 'Emergency Stop'}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-end">
              <div className="space-y-1">
                <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Shift Production</span>
                <div className="text-3xl font-black text-white tabular-nums tracking-tighter">{stats.produced} <span className="text-slate-800 text-lg">/ 500</span></div>
              </div>
              <div className="text-right">
                <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Efficiency</span>
                <div className="text-sm font-bold text-indigo-400 tracking-tight">{((stats.produced / 500) * 100).toFixed(1)}%</div>
              </div>
            </div>
            <div className="h-2.5 w-full bg-slate-950 rounded-full overflow-hidden border border-slate-900 p-[2px]">
               <div className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.4)] transition-all duration-1000 ease-out" style={{ width: `${(stats.produced / 500) * 100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/40 p-1.5 mx-8 my-6 rounded-xl border border-slate-900/50">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" />, label: 'Analytics' },
            { id: 'QUALITY', icon: <ShieldAlert className="w-4 h-4" />, label: 'Repair' },
            { id: 'NODES', icon: <LayoutGrid className="w-4 h-4" />, label: 'Nodes' }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as DashboardTab)} className={`flex-1 flex flex-col items-center gap-1.5 py-3 rounded-lg transition-all ${activeTab === tab.id ? 'bg-indigo-500/10 text-indigo-400 shadow-sm' : 'text-slate-600 hover:text-slate-400'}`}>
              {tab.icon}
              <span className="text-[8px] font-black uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-8 pb-8 space-y-10">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-700">
              <section className="space-y-4">
                <header className="text-[10px] font-black text-slate-700 uppercase tracking-[0.25em] flex items-center gap-2"><ActivitySquare className="w-3.5 h-3.5" /> Roll Cabin Telemetry</header>
                <div className="grid grid-cols-3 gap-3">
                  {cabins.map((v, i) => (
                    <div key={i} className={`p-4 rounded-2xl border flex flex-col items-center gap-3 transition-all duration-500 ${v ? 'bg-indigo-500/10 border-indigo-500/30 shadow-[0_10px_30px_rgba(99,102,241,0.1)]' : 'bg-slate-900/30 border-slate-900/50'}`}>
                      <div className={`p-2 rounded-lg ${v ? 'bg-indigo-500 text-white' : 'bg-slate-800 text-slate-600'}`}>
                        <Gauge className="w-4 h-4" />
                      </div>
                      <div className="text-center space-y-1">
                        <span className={`text-[8px] font-black uppercase tracking-widest ${v ? 'text-indigo-400' : 'text-slate-700'}`}>{v ? 'In-Test' : 'Standby'}</span>
                        <div className="text-[10px] font-black text-slate-200">{v ? `#${v.id.toUpperCase()}` : '--'}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </section>

              <section className="grid grid-cols-2 gap-4">
                <div className="p-5 bg-slate-900/40 border border-slate-900/50 rounded-2xl group hover:border-emerald-500/30 transition-all cursor-default">
                  <div className="flex items-center gap-2 mb-3">
                    <div className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                    <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">FTT Rate</span>
                  </div>
                  <div className="text-3xl font-black text-emerald-400 tabular-nums">{fttRate.toFixed(1)}<span className="text-xs ml-1">%</span></div>
                </div>
                <div className="p-5 bg-slate-900/40 border border-slate-900/50 rounded-2xl group hover:border-indigo-500/30 transition-all cursor-default">
                  <div className="flex items-center gap-2 mb-3">
                    <div className="w-1.5 h-1.5 rounded-full bg-indigo-500" />
                    <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">FTR Index</span>
                  </div>
                  <div className="text-3xl font-black text-indigo-400 tabular-nums">{ftrRate.toFixed(1)}<span className="text-xs ml-1">%</span></div>
                </div>
              </section>

              <section className="p-6 bg-slate-900/20 rounded-3xl border border-slate-900/50 space-y-6">
                <header className="flex justify-between items-center text-[10px] font-black text-slate-700 uppercase tracking-widest">
                  <span>Defect Distribution</span>
                  <Activity className="w-3.5 h-3.5" />
                </header>
                <div className="space-y-6">
                  {Object.entries(stats.categoryVolumes).map(([cat, val]) => (
                    <div key={cat} className="space-y-2">
                      <div className="flex justify-between text-[9px] font-black uppercase tracking-tight">
                        <span className="text-slate-500">{cat}</span>
                        <span className="text-slate-300">{val}</span>
                      </div>
                      <div className="h-1.5 w-full bg-slate-950 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500/50 transition-all duration-1000" style={{ width: `${(val / (stats.defects || 1)) * 100}%` }} />
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="space-y-6 animate-in fade-in duration-700">
               <header className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-slate-600">
                 <span>Resolution Cell</span>
                 <span className="px-3 py-1 bg-rose-500 text-white rounded-full text-[8px] font-black">{vehiclesRef.current.filter(v=>v.inRepair).length} UNITS</span>
               </header>
               <div className="space-y-4">
                  {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                    <div key={v.id} className="p-6 bg-slate-900/50 border border-slate-900 rounded-3xl space-y-5 hover:border-indigo-500/40 transition-all group">
                       <div className="flex justify-between items-center">
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-4 rounded-sm shadow-inner" style={{ backgroundColor: v.color }} />
                            <span className="text-[11px] font-black text-white tracking-widest">UNIT-{v.id.toUpperCase()}</span>
                          </div>
                          <span className="text-[9px] font-black text-slate-600 tabular-nums">T+ {((v.currentLeadTime||0)/60).toFixed(0)}S</span>
                       </div>
                       <div className="flex items-center gap-4 py-3 px-4 bg-slate-950 rounded-2xl border border-slate-900">
                         <AlertCircle className="w-4 h-4 text-rose-500" />
                         <div className="flex flex-col">
                           <span className="text-[8px] font-black text-slate-700 uppercase">System Fault</span>
                           <span className="text-[10px] font-bold text-rose-500 tracking-tight">{v.failureType}</span>
                         </div>
                       </div>
                       <button onClick={() => unlockVehicle(v.id)} className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-900/20 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all active:scale-95">Re-Sync System</button>
                    </div>
                  ))}
                  {vehiclesRef.current.filter(v=>v.inRepair).length === 0 && (
                    <div className="py-24 flex flex-col items-center justify-center opacity-10">
                      <CheckCircle2 className="w-20 h-20 mb-6 text-emerald-500" />
                      <span className="text-[10px] font-black uppercase tracking-[0.5em]">Sync Status: Clear</span>
                    </div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'NODES' && (
            <div className="space-y-6 animate-in fade-in duration-700">
              <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-700" />
                <input type="text" placeholder="Filter Station ID..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-slate-950 border border-slate-900 rounded-2xl py-4 pl-12 pr-4 text-[10px] font-black uppercase tracking-widest focus:outline-none focus:border-indigo-500/50 transition-all placeholder:text-slate-800" />
              </div>
              <div className="space-y-2">
                {[...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].filter(s=>s.name.toUpperCase().includes(searchTerm.toUpperCase())).map(s => (
                  <div key={s.id} onMouseEnter={() => setHoveredStationId(s.id)} onMouseLeave={() => setHoveredStationId(null)} className={`px-5 py-4 rounded-xl border flex items-center justify-between transition-all cursor-default ${hoveredStationId === s.id ? 'bg-indigo-500/10 border-indigo-500/30' : 'bg-transparent border-transparent hover:bg-slate-900/20'}`}>
                     <div className="flex items-center gap-4">
                       <div className={`w-2 h-2 rounded-full ${s.type === 'TEST' ? 'bg-indigo-500' : (s.type === 'QUALITY' ? 'bg-emerald-500' : 'bg-slate-800')}`} />
                       <span className={`text-[10px] font-black transition-colors tracking-tight ${hoveredStationId === s.id ? 'text-indigo-400' : 'text-slate-500'}`}>{s.name}</span>
                     </div>
                     <span className="text-[8px] font-black text-slate-800 uppercase px-2 py-0.5 border border-slate-800 rounded">{s.type}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Global Controls */}
        <div className="p-8 border-t border-slate-900 bg-slate-950/40 backdrop-blur-md space-y-4">
           <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setIsRunning(!isRunning)} className={`py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center ${isRunning ? 'bg-slate-900 text-slate-500 border border-slate-800 hover:bg-slate-800' : 'bg-indigo-600 text-white shadow-2xl shadow-indigo-900/40'}`}>
                 {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4 fill-current" />} {isRunning ? 'Hold' : 'Resume'}
              </button>
              <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,cycleTime:0,totalStarted:0,passedFirstTime:0,totalRepaired:0,repairAttempts:0,totalStagesCompleted:0,totalLeadTimeFrames:0,repairCompletedCount:0,ftrFails:0,ftrSuccesses:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},totalWaitAreaEntries:0,rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); }} className="py-4 bg-slate-900 text-slate-700 hover:text-rose-500 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center border border-transparent hover:border-rose-900/20">
                <RotateCcw className="w-4 h-4" /> Reset
              </button>
           </div>
           <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; v.waitingTimer = 0; v.ignoreCollisionTimer = 120; }); addLog("SYSTEM RE-CALIBRATED"); }} className="w-full py-4 bg-indigo-500/5 border border-indigo-500/10 hover:border-indigo-500/30 text-indigo-400 hover:text-indigo-300 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center active:scale-95">
             <Key className="w-4 h-4" /> Overwrite All Locks
           </button>
        </div>
      </aside>

      {/* Main Simulation Viewport */}
      <main className="flex-1 relative flex flex-col bg-[#01040a]">

        {/* Header HUD */}
        <header className="h-20 border-b border-slate-900/50 flex items-center justify-between px-10 bg-[#020617]/50 backdrop-blur-xl z-20 shrink-0">
          <div className="flex gap-10">
            <div className="flex flex-col">
              <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest mb-1">Live Feed</span>
              <div className="flex items-center gap-2 text-[13px] font-bold text-slate-200">
                <Activity className="w-4 h-4 text-indigo-500" /> Plant 01: Assembly_Area
              </div>
            </div>
            <div className="flex flex-col border-l border-slate-900 pl-10">
              <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest mb-1">Active Units</span>
              <div className="flex items-center gap-2 text-[13px] font-bold text-indigo-400">
                <Cpu className="w-4 h-4" /> {stats.active} Nodes
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4 bg-slate-950 p-2 rounded-2xl border border-slate-900">
             <div className="px-4 py-2 bg-indigo-500/10 rounded-xl">
               <span className="text-[10px] font-black text-indigo-400 uppercase tracking-tighter">Calibration: Optimal</span>
             </div>
          </div>
        </header>

        {/* Dedicated Viewport Wrapper for Centering */}
        <div ref={viewportRef} className="flex-1 flex items-center justify-center relative bg-dot-pattern overflow-hidden">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center center',
              transition: 'transform 0.6s cubic-bezier(0.23, 1, 0.32, 1)'
            }} 
            className="relative bg-[#020617] rounded-[3rem] shrink-0 overflow-hidden border border-slate-900 shadow-[0_40px_100px_rgba(0,0,0,0.8)] flex items-center justify-center"
          >
            {/* Grid Blueprint Overlay */}
            <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#1e293b 1px, transparent 1px)', backgroundSize: '24px 24px' }} />

            <canvas ref={canvasRef} className="relative z-10" />

            {/* Branding Inset */}
            <div className="absolute top-14 left-14 opacity-20 pointer-events-none select-none">
              <h2 className="text-[20px] font-black text-slate-700 uppercase tracking-[0.8em]">AUTOMATA_LINE</h2>
            </div>
          </div>
        </div>

        {/* Footer Ticker */}
        <footer className="h-16 bg-[#020617] border-t border-slate-900 flex items-center px-10 gap-10 shrink-0 overflow-hidden text-[9px] font-black uppercase tracking-[0.3em] text-slate-700 z-20">
          <div className="flex items-center gap-3 text-indigo-500 shrink-0 border-r border-slate-900 pr-10 h-full"><Terminal className="w-4 h-4" /> EVENT_LOG</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-20 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-3 items-center ${l.includes('FAILED') ? 'text-rose-500' : 'text-slate-500'}`}><div className={`w-1.5 h-1.5 rounded-full ${l.includes('FAILED') ? 'bg-rose-500 animate-pulse' : 'bg-slate-800'}`} /> {l}</span>
              ))}
              {logs.length === 0 && <span className="opacity-30 italic">Monitoring Industrial IoT Mesh... System Ready.</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 50s linear infinite; }
        .animate-in { animation: animateIn 0.8s ease-out forwards; }
        @keyframes animateIn { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
        .bg-dot-pattern {
          background-image: radial-gradient(rgba(30, 41, 59, 0.2) 1px, transparent 1px);
          background-size: 40px 40px;
        }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, 
  Pause, 
  RotateCcw, 
  CheckCircle2,
  ShieldAlert,
  Search,
  Terminal,
  Key,
  BarChart,
  LayoutGrid,
  AlertCircle,
  Gauge,
  Zap,
  ActivitySquare,
  Radio,
  Activity,
  Cpu,
  Boxes
} from 'lucide-react';
import { 
  SIM_WIDTH, 
  SIM_HEIGHT, 
  COLORS, 
  MAIN_PATH_POINTS, 
  REPAIR_PATH_POINTS, 
  STATIONS, 
  REPAIR_STATIONS,
  ROLL_TEST_BRANCHES,
  FORK_POINT_IDX,
  MERGE_POINT_IDX,
  PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

type DashboardTab = 'NODES' | 'KPI' | 'QUALITY';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<DashboardTab>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(420);
  const [speed] = useState(3.2);
  const [defectRate] = useState(0.18); 
  const [scale, setScale] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, cycleTime: 0, totalStarted: 0, passedFirstTime: 0, 
    totalRepaired: 0, repairAttempts: 0, totalStagesCompleted: 0, totalLeadTimeFrames: 0, 
    repairCompletedCount: 0, ftrFails: 0, ftrSuccesses: 0, 
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    totalWaitAreaEntries: 0, rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);
  const [hoveredStationId, setHoveredStationId] = useState<string | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  // Precision Scaling and Auto-Centering logic
  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;

    // Using getBoundingClientRect for accurate pixel values including subpixels
    const rect = viewportRef.current.getBoundingClientRect();
    const availableWidth = rect.width;
    const availableHeight = rect.height;

    // Safety padding for aesthetics
    const padding = 100;

    const scaleX = (availableWidth - padding) / SIM_WIDTH;
    const scaleY = (availableHeight - padding) / SIM_HEIGHT;

    // Maintain aspect ratio while fitting into viewport
    const newScale = Math.min(scaleX, scaleY);
    setScale(Math.max(0.05, newScale));

    // Handle HiDPI Canvas Rendering
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) {
      ctx.resetTransform();
      ctx.scale(dpr, dpr);
    }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    // Initial scale calculation with a slight delay for DOM readiness
    const timer = setTimeout(updateScale, 50);

    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };

    return () => {
      window.removeEventListener('resize', updateScale);
      clearTimeout(timer);
    };
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasEngine: false, hasWheels: false, hasFluids: false, hasDefect: Math.random() < defectRate,
      isRepaired: false, inRepair: false, color: bodyColor, baseColor: bodyColor, finished: false, progress: 0,
      everRepaired: false, ignoreCollisionTimer: 0, pendingRepairs: 0, completedRepairs: 0, initialRepairs: 0,
      isLocked: false, failureType: null, lastFailureType: null, workOrderId: null, repairStartTime: null,
      currentLeadTime: 0, faiStatus: 'NONE', waterTestStatus: 'NONE', finalInspectionStatus: 'NONE',
      everEnteredWaitingArea: false, waitingAreaEntryCount: 0, isFtrNegative: false, viaVerde: true,
      repairCycleCount: 0, inRetest: false, rollTestStatus: 'NONE', rollTestFailType: null, assignedCabinId: null,
      rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, [defectRate]);

  const unlockVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; 
      v.waitingTimer = 0; 
      v.ignoreCollisionTimer = 60; 
      addLog(`UNIT ${v.id.toUpperCase()} VERIFIED & RELEASED`); 
    }
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair && v.repairStartTime !== null) v.currentLeadTime = frameCountRef.current - v.repairStartTime;
      if (v.ignoreCollisionTimer > 0) v.ignoreCollisionTimer--;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
        if (cabin) {
            const totalWait = cabin.wait;
            const elapsed = totalWait - v.waitingTimer;
            if (elapsed < totalWait * 0.33) v.rollStep = 'ECATS';
            else if (elapsed < totalWait * 0.66) v.rollStep = 'ACCEL';
            else if (v.waitingTimer > 0) v.rollStep = 'BRAKE';
            else v.rollStep = 'DONE';
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      const hasBlocker = currentVehicles.some(o => {
          if (o.id === v.id) return false;
          const d = Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2));
          return d < 65 && o.pathIdx >= v.pathIdx;
      });
      if (v.ignoreCollisionTimer <= 0 && hasBlocker) continue;

      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && !v.assignedCabinId && v.rollTestStatus !== 'PASS') {
            const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
            if (availableIdx !== undefined) {
                v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
                v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
                v.pathIdx = 0;
            } else { v.pathIdx--; continue; }
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 2 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 2) {
            v.assignedCabinId = null;
            v.rollStep = 'READY';
        }

        const currentMap = v.inRepair ? REPAIR_STATIONS : STATIONS;
        let station = currentMap[v.pathIdx] || PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;
          const routeToRepair = (source: string, type: FailureType) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type; 
            v.repairStartTime = frameCountRef.current;
            v.workOrderId = `SO-${Math.floor(Math.random() * 9000 + 1000)}`;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0; v.color = COLORS.REPAIR;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`${v.id.toUpperCase()}: ${source} FAILED [${type}]`);
          };

          if (station.name.startsWith('Teste Rolo')) {
             const isDefective = v.hasDefect && Math.random() < 0.4;
             if (isDefective) {
                const rollFailType: RollFailureType = Math.random() < 0.6 ? 'ECATS' : 'VELOCITY';
                v.rollTestStatus = 'FAIL'; v.rollTestFailType = rollFailType;
                if (rollFailType === 'ECATS') { setStats(s => ({ ...s, ecatsFailures: s.ecatsFailures + 1 })); routeToRepair('ROLL (ECATS)', 'ELECTRONIC'); }
                else { setStats(s => ({ ...s, velocityFailures: s.velocityFailures + 1 })); routeToRepair('ROLL (ACCEL)', 'MECHANICAL'); }
             } else { 
               v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); 
             }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.rollTestStatus !== 'PASS' && !v.inRepair) routeToRepair('BYPASS PREVENTED', 'MECHANICAL');
            else if (Math.random() < 0.08) { v.waterTestStatus = 'FAIL'; routeToRepair('WATER LEAK', 'LEAKAGE'); }
            else v.waterTestStatus = 'PASS';
          }

          if (v.inRepair && station.name === 'ÁREA BRANCA') {
            v.inRepair = false; v.color = v.baseColor;
            setStats(s => ({ ...s, repairCompletedCount: s.repairCompletedCount + 1, ftrSuccesses: s.ftrSuccesses + 1 }));
            if (v.failureType === 'LEAKAGE') { v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 18; }
            else { v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 10; }
          }
        }
      } else { const r = speed / dist; v.pos.x += dx * r; v.pos.y += dy * r; }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Industrial Grid Rendering
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=50) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=50) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const drawPath = (pts: Point[], col = 'rgba(30, 41, 59, 0.8)', w = 24) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
      ctx.beginPath(); ctx.strokeStyle = 'rgba(255,255,255,0.03)'; ctx.lineWidth = 2;
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    drawPath(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1), '#1e293b', 30);
    ROLL_TEST_BRANCHES.forEach(b => drawPath(b, '#0f172a', 36));
    drawPath(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX), '#1e293b', 30);
    drawPath(REPAIR_PATH_POINTS, '#180a0a', 34);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRollTest = s.name.startsWith('Teste Rolo');
      const w = s.width || (isRollTest ? 140 : 100), h = s.height || (isRollTest ? 64 : 42), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(veh => Math.abs(veh.pos.x - s.pos.x) < 8 && Math.abs(veh.pos.y - s.pos.y) < 8);
      let status = vehicleIn ? (vehicleIn.waitingTimer > 0 ? 'PROCESSING' : 'OCCUPIED') : 'IDLE';

      ctx.shadowBlur = 10; ctx.shadowColor = 'rgba(0,0,0,0.5)';
      ctx.fillStyle = isRollTest ? '#020617' : '#0f172a'; 
      ctx.strokeStyle = isRollTest ? (status === 'PROCESSING' ? '#6366f1' : '#1e293b') : 'rgba(255,255,255,0.05)';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      ctx.fillStyle = status === 'PROCESSING' ? '#10b981' : (status === 'OCCUPIED' ? '#f59e0b' : '#334155');
      ctx.beginPath(); ctx.arc(x + 16, y + 14, 4, 0, Math.PI * 2); ctx.fill();
      ctx.fillStyle = '#94a3b8'; ctx.font = `bold ${isRollTest ? '11px' : '9px'} Inter`; 
      ctx.fillText(s.name.toUpperCase(), x + 28, y + 18);

      if (isRollTest && vehicleIn) {
        ctx.fillStyle = 'rgba(99, 102, 241, 0.1)'; ctx.beginPath(); ctx.roundRect(x + 8, y + 32, w - 16, 22, 6); ctx.fill();
        ctx.fillStyle = '#6366f1'; ctx.font = '800 9px Inter';
        ctx.fillText(`${vehicleIn.rollStep}`, x + 16, y + 46);
        const prog = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = 'rgba(99, 102, 241, 0.2)'; ctx.fillRect(x + 50, y + 40, w - 70, 4);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 50, y + 40, (w - 70) * prog, 4);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 8; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; 
      ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      if (v.assignedCabinId && v.waitingTimer > 0) {
        ctx.fillStyle = 'rgba(2, 6, 23, 0.9)'; ctx.beginPath(); ctx.roundRect(v.pos.x - 45, v.pos.y - 50, 90, 22, 6); ctx.fill();
        ctx.strokeStyle = '#6366f1'; ctx.lineWidth = 1; ctx.stroke();
        ctx.fillStyle = '#fff'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
        ctx.fillText(`${v.rollStep} RUNNING`, v.pos.x, v.pos.y - 36);
        ctx.textAlign = 'start';
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; 
    const loop = () => { 
      updateSimulation(); 
      if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); 
      fId = requestAnimationFrame(loop); 
    };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const fttRate = stats.produced > 0 ? (stats.passedFirstTime / stats.produced) * 100 : 0;
  const ftrRate = stats.repairCompletedCount > 0 ? (stats.ftrSuccesses / stats.repairCompletedCount) * 100 : 0;
  const cabins = [0, 1, 2].map(i => vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id));

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden selection:bg-indigo-500/30">

      {/* Sidebar: Control Center */}
      <aside className="w-[400px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="p-8 border-b border-slate-900/50 space-y-8 bg-gradient-to-b from-indigo-500/5 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-500 rounded-xl shadow-[0_0_20px_rgba(99,102,241,0.4)]">
                <Boxes className="w-5 h-5 text-white" />
              </div>
              <div>
                <h1 className="text-[11px] font-black tracking-[0.3em] text-white uppercase">VPD SIMULATOR</h1>
                <p className="text-[9px] font-bold text-slate-500 tracking-wider">CORE SYSTEM OPS</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[9px] font-black uppercase tracking-widest`}>
