  1: { id: 'r1', name: 'Buffer Resolução', pos: REPAIR_PATH_POINTS[1], wait: 100, type: StationType.REPAIR, width: 140 },
  2: { id: 'r2', name: 'Reparo Estanqueidade', pos: REPAIR_PATH_POINTS[2], wait: 200, type: StationType.REPAIR, width: 150 },
  3: { id: 'r3', name: 'Reparo Eletrônico', pos: REPAIR_PATH_POINTS[3], wait: 150, type: StationType.REPAIR, width: 150 }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Search, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Cpu, Boxes, Droplets, ArrowRight
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType, QualityStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'KPI' | 'QUALITY' | 'NODES'>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(450); 
  const [speed] = useState(3.5);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0, taktAlerts: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 80) / SIM_WIDTH, (rect.height - 80) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.22, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', flatTopStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, inRepair: false, assignedCabinId: null, rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      // Takt Time Monitoring & Repair Timer
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;

        // Protocolo de Rolo: ECATS -> ACCEL -> BRAKE
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      // Colisão & Cadência
      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 60 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        // Gatekeeper: Teste de Rolo (3 Cabines)
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE') {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } // Aguarda vaga na cabine
        }

        // Liberação de Cabine no Merge
        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        const station = (v.inRepair ? REPAIR_STATIONS : STATIONS)[v.pathIdx] || 
                        PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const fail = (type: FailureType, source: string) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type;
            v.color = COLORS.DANGER;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`ALERTA: ${v.id.toUpperCase()} FALHOU EM ${source} [${type}]`);
          };

          // Lógicas de Validação por Estação
          if (station.name.startsWith('Rolo')) {
            if (v.hasDefect && Math.random() < 0.3) {
              v.rollTestStatus = 'FAIL';
              fail(Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLO');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.15) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              fail('LEAKAGE', 'H2O TEST');
            } else { v.waterTestStatus = 'PASS'; v.needsH2ORetesting = false; }
          }

          if (station.name === 'FLAT-TOP FINAL') {
            if (v.hasDefect && Math.random() < 0.1) {
              v.flatTopStatus = 'FAIL';
              // Desvio para Pre-Delivery forçado via caminho principal
              addLog(`FLAT-TOP NOK: ${v.id.toUpperCase()} -> DESVIO PRE-DELIVERY`);
            } else { v.flatTopStatus = 'PASS'; }
          }

          if (v.inRepair && station.name === 'BUFFER RESOLUÇÃO') {
            // Unidade parada aguardando liberação manual no dashboard
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid Industrial
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.3)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const path = (pts: Point[], col = '#1e293b', w = 30) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    path(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => path(b, '#0f172a', 40));
    path(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    path(REPAIR_PATH_POINTS, '#180a0a', 36);

    // Render Estações
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Rolo');
      const w = s.width || (isRoll ? 140 : 120), h = s.height || (isRoll ? 64 : 44), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      ctx.fillStyle = isRoll ? '#020617' : '#0f172a';
      ctx.strokeStyle = vIn && vIn.waitingTimer > 0 ? COLORS.SUCCESS : '#1e293b';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 12); ctx.fill(); ctx.stroke();

      ctx.fillStyle = '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 18);

      if (vIn && vIn.waitingTimer > 0) {
        const p = 1 - (vIn.waitingTimer / s.wait);
        ctx.fillStyle = '#1e293b'; ctx.fillRect(x + 10, y + 35, w - 20, 6);
        ctx.fillStyle = COLORS.SUCCESS; ctx.fillRect(x + 10, y + 35, (w - 20) * p, 6);
        if (isRoll) {
            ctx.fillStyle = '#6366f1'; ctx.font = 'black 8px Inter';
            ctx.fillText(vIn.rollStep, s.pos.x, y + 55);
        }
      }
    });

    // Render Veículos
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 10; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const releaseVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));
      if (v.needsH2ORetesting) {
        v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 16; // Retorno direto para Agua
      } else {
        v.targetPath = [...MAIN_PATH_POINTS]; v.pathIdx = 15; // FAI re-check
      }
      addLog(`REPARO CONCLUÍDO: ${v.id.toUpperCase()} RE-SINCRONIZADO`);
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      {/* Sidebar de Gestão (GOP) */}
      <aside className="w-[420px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl">
        <div className="p-8 border-b border-slate-900/50 space-y-8 bg-gradient-to-b from-indigo-500/5 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-indigo-600 rounded-2xl shadow-indigo-500/20 shadow-lg"><Boxes className="w-5 h-5 text-white" /></div>
              <div>
                <h1 className="text-[12px] font-black tracking-widest text-white uppercase">GOP Dashboard</h1>
                <p className="text-[9px] font-bold text-slate-600 uppercase tracking-tighter">Meta: 500 VPD</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[9px] font-black uppercase tracking-widest`}>
               <Radio className={`w-3 h-3 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Line Live' : 'Line Halted'}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-end">
              <div className="space-y-1">
                <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest">Ritmo de Produção</span>
                <div className="text-4xl font-black text-white tabular-nums tracking-tighter">{stats.produced} <span className="text-slate-800 text-xl">/ 500</span></div>
              </div>
              <div className="text-right text-indigo-400 font-bold text-sm">
                {((stats.produced/500)*100).toFixed(1)}%
              </div>
            </div>
            <div className="h-3 w-full bg-slate-950 rounded-full border border-slate-900 p-0.5">
               <div className="h-full bg-indigo-500 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.5)] transition-all duration-1000" style={{ width: `${(stats.produced/500)*100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/40 p-2 mx-6 my-6 rounded-2xl border border-slate-900">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" />, label: 'Metas' },
            { id: 'QUALITY', icon: <ShieldAlert className="w-4 h-4" />, label: 'Buffer' },
            { id: 'NODES', icon: <LayoutGrid className="w-4 h-4" />, label: 'Gargalos' }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 flex flex-col items-center gap-1.5 py-3 rounded-xl transition-all ${activeTab === tab.id ? 'bg-indigo-600/10 text-indigo-400 shadow-inner' : 'text-slate-700 hover:text-slate-500'}`}>
              {tab.icon}
              <span className="text-[8px] font-black uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-8 pb-8 space-y-10">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <section className="grid grid-cols-2 gap-4">
                <div className="p-5 bg-slate-900/30 border border-slate-900 rounded-3xl group hover:border-emerald-500/20 transition-all">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-emerald-500" /> FTT (First Time)</span>
                  <div className="text-3xl font-black text-emerald-400 mt-2">{((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%</div>
                </div>
                <div className="p-5 bg-slate-900/30 border border-slate-900 rounded-3xl group hover:border-indigo-500/20 transition-all">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-indigo-500" /> FTR (Repair OK)</span>
                  <div className="text-3xl font-black text-indigo-400 mt-2">{((stats.ftrSuccesses / (stats.repairCompletedCount || 1)) * 100).toFixed(1)}%</div>
                </div>
              </section>

              <section className="space-y-4">
                <header className="text-[10px] font-black text-slate-700 uppercase tracking-widest flex items-center gap-2"><ActivitySquare className="w-3.5 h-3.5" /> Ocupação Cabines de Rolo</header>
                <div className="grid grid-cols-3 gap-3">
                  {[0,1,2].map(i => {
                    const occ = vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id);
                    return (
                      <div key={i} className={`p-4 rounded-2xl border flex flex-col items-center gap-2 transition-all ${occ ? 'bg-indigo-500/10 border-indigo-500/40 shadow-lg shadow-indigo-900/10' : 'bg-slate-900/20 border-slate-900'}`}>
                        <Gauge className={`w-4 h-4 ${occ ? 'text-indigo-400 animate-pulse' : 'text-slate-800'}`} />
                        <span className={`text-[8px] font-black uppercase ${occ ? 'text-indigo-300' : 'text-slate-800'}`}>{occ ? occ.rollStep : 'LIVRE'}</span>
                      </div>
                    );
                  })}
                </div>
              </section>

              <section className="p-6 bg-slate-900/40 border border-slate-900 rounded-3xl space-y-6 shadow-xl">
                 <header className="flex justify-between items-center text-[10px] font-black text-slate-700 uppercase tracking-widest">
                   <span>Falhas por Categoria</span>
                   <Zap className="w-4 h-4" />
                 </header>
                 <div className="space-y-6">
                   {Object.entries(stats.categoryVolumes).map(([cat, val]) => (
                     <div key={cat} className="space-y-2">
                        <div className="flex justify-between text-[9px] font-black uppercase">
                          <span className="text-slate-500">{cat}</span>
                          <span className="text-slate-300">{val}</span>
                        </div>
                        <div className="h-1.5 w-full bg-slate-950 rounded-full overflow-hidden">
                           <div className="h-full bg-indigo-500/50 transition-all duration-1000" style={{ width: `${(val / (stats.defects || 1)) * 100}%` }} />
                        </div>
                     </div>
                   ))}
                 </div>
              </section>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <header className="flex justify-between items-center text-[10px] font-black text-slate-600 uppercase tracking-widest">
                <span>Aguardando Reparo Técnica</span>
                <span className="px-3 py-1 bg-rose-500/20 text-rose-500 rounded-full text-[8px] font-black border border-rose-500/20">{vehiclesRef.current.filter(v=>v.isLocked).length} PENDENTES</span>
              </header>
              <div className="space-y-4">
                {vehiclesRef.current.filter(v=>v.isLocked).map(v => (
                  <div key={v.id} className="p-6 bg-slate-900/50 border border-slate-900 rounded-3xl space-y-6 hover:border-indigo-500/40 transition-all group shadow-2xl">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-4 rounded-sm shadow-inner" style={{ backgroundColor: v.color }} />
                        <span className="text-[11px] font-black text-white tracking-widest">VIN-{v.id.toUpperCase()}</span>
                      </div>
                      <div className="flex items-center gap-1.5 text-rose-500 font-black text-[9px] uppercase"><AlertCircle className="w-3 h-3" /> {v.failureType}</div>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <div className="p-3 bg-slate-950 rounded-xl border border-slate-900">
                          <span className="text-[8px] font-black text-slate-700 uppercase block mb-1">H2O Status</span>
                          <span className={`text-[10px] font-bold ${v.waterTestStatus === 'FAIL' ? 'text-rose-500' : 'text-slate-500'}`}>{v.waterTestStatus}</span>
                        </div>
                        <div className="p-3 bg-slate-950 rounded-xl border border-slate-900">
                          <span className="text-[8px] font-black text-slate-700 uppercase block mb-1">Roll Status</span>
                          <span className="text-[10px] font-bold text-slate-500">{v.rollTestStatus}</span>
                        </div>
                    </div>
                    <button onClick={() => releaseVehicle(v.id)} className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white text-[10px] font-black uppercase tracking-[0.2em] rounded-2xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2">
                       <ArrowRight className="w-4 h-4" /> Validar & Liberar
                    </button>
                  </div>
                ))}
                {vehiclesRef.current.filter(v=>v.isLocked).length === 0 && (
                  <div className="py-24 flex flex-col items-center justify-center opacity-10">
                    <CheckCircle2 className="w-20 h-20 mb-6 text-emerald-500" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em]">Tudo Sincronizado</span>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        <div className="p-8 border-t border-slate-900 bg-slate-950/40 space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => setIsRunning(!isRunning)} className={`py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center ${isRunning ? 'bg-slate-900 text-slate-600' : 'bg-indigo-600 text-white shadow-2xl shadow-indigo-900/40'}`}>
               {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'Hold' : 'Resume'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("SISTEMA RESETADO"); }} className="py-4 bg-slate-900 text-slate-700 hover:text-rose-500 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center border border-transparent hover:border-rose-900/20">
              <RotateCcw className="w-4 h-4" /> Reset
            </button>
          </div>
          <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; }); }} className="w-full py-4 bg-indigo-500/5 border border-indigo-500/10 hover:border-indigo-500/30 text-indigo-400 text-[10px] font-black uppercase tracking-widest rounded-2xl transition-all flex justify-center items-center gap-3 active:scale-95 shadow-lg">
             <Key className="w-4 h-4" /> Forçar Sincronismo Global
          </button>
        </div>
      </aside>

      {/* Viewport Principal */}
      <main className="flex-1 relative flex flex-col bg-[#01040a]">

        {/* HUD Superior */}
        <header className="h-20 border-b border-slate-900/50 flex items-center justify-between px-10 bg-[#020617]/50 backdrop-blur-xl z-20 shrink-0">
          <div className="flex gap-12">
            <div className="flex flex-col">
              <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest mb-1">Unidades Ativas</span>
              <div className="flex items-center gap-3 text-[14px] font-black text-slate-200">
                <Cpu className="w-4 h-4 text-indigo-500" /> {stats.active} Nodes
              </div>
            </div>
            <div className="flex flex-col border-l border-slate-900 pl-12">
              <span className="text-[9px] font-black text-slate-700 uppercase tracking-widest mb-1">Takt Eficácia</span>
              <div className="flex items-center gap-3 text-[14px] font-black text-emerald-400">
                <Gauge className="w-4 h-4" /> Nominal
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4 bg-slate-950 p-2 rounded-2xl border border-slate-900 shadow-xl">
             <div className="px-5 py-2.5 bg-indigo-500/10 rounded-xl border border-indigo-500/20">
               <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-3"><Zap className="w-3.5 h-3.5" /> High Precision OPS</span>
             </div>
          </div>
        </header>

        <div ref={viewportRef} className="flex-1 flex items-center justify-center relative bg-dot-pattern overflow-hidden p-12">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center center',
              transition: 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)'
            }} 
            className="relative bg-[#020617] rounded-[4rem] shrink-0 overflow-hidden border-2 border-slate-800 shadow-[0_80px_160px_-20px_rgba(0,0,0,1)] flex items-center justify-center"
          >
            <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#334155 1.5px, transparent 1.5px)', backgroundSize: '32px 32px' }} />
            <canvas ref={canvasRef} className="relative z-10" />
            <div className="absolute top-16 left-16 opacity-10 pointer-events-none select-none">
              <h2 className="text-[28px] font-black text-slate-700 uppercase tracking-[1.2em]">FINAL_ASSEMBLY_500VPD</h2>
            </div>
            <div className="absolute inset-6 border border-slate-900/40 rounded-[3.5rem] pointer-events-none" />
          </div>
        </div>

        {/* Footer Log */}
        <footer className="h-16 bg-[#020617] border-t border-slate-900 flex items-center px-10 gap-10 shrink-0 overflow-hidden text-[9px] font-black uppercase tracking-[0.3em] text-slate-700 z-20">
          <div className="flex items-center gap-3 text-indigo-500 shrink-0 border-r border-slate-900 pr-10 h-full"><Terminal className="w-4 h-4" /> IIoT BUS</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-20 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-3 items-center ${l.includes('ALERTA') ? 'text-rose-500' : 'text-slate-600'}`}>
                  <div className={`w-1.5 h-1.5 rounded-full ${l.includes('ALERTA') ? 'bg-rose-500 animate-pulse' : 'bg-slate-800'}`} /> {l}
                </span>
              ))}
              {logs.length === 0 && <span className="opacity-30 italic">Monitoring Assembly Line Alpha... Connection: Nominal.</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 60s linear infinite; }
        .bg-dot-pattern {
          background-image: radial-gradient(rgba(30, 41, 59, 0.2) 1.5px, transparent 1.5px);
          background-size: 40px 40px;
        }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Search, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Cpu, Boxes, Droplets, ArrowRight, Monitor
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType, QualityStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'KPI' | 'QUALITY' | 'NODES'>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(480); 
  const [speed] = useState(3.5);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0, taktAlerts: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    // Aumento da área de visualização: Redução do padding para 40px
    const s = Math.min((rect.width - 40) / SIM_WIDTH, (rect.height - 40) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));

    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6);
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.20, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', flatTopStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, inRepair: false, assignedCabinId: null, rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 

      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 62 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE') {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        const station = (v.inRepair ? REPAIR_STATIONS : STATIONS)[v.pathIdx] || 
                        PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const fail = (type: FailureType, source: string) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type;
            v.color = COLORS.DANGER;
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`GOP ALERTA: VIN ${v.id.toUpperCase()} FALHA TÉCNICA EM ${source}`);
          };

          if (station.name.startsWith('Rolo')) {
            if (v.hasDefect && Math.random() < 0.28) {
              v.rollTestStatus = 'FAIL';
              fail(Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLO OPS');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.12) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              fail('LEAKAGE', 'H2O SCAN');
            } else { v.waterTestStatus = 'PASS'; v.needsH2ORetesting = false; }
          }

          if (station.name === 'FLAT-TOP FINAL') {
            if (v.hasDefect && Math.random() < 0.08) {
              v.flatTopStatus = 'FAIL';
              addLog(`FLAT-TOP NOK: VIN ${v.id.toUpperCase()} REDIRECIONADO PRE-DELIVERY`);
            } else { v.flatTopStatus = 'PASS'; }
          }

          if (v.inRepair && station.name === 'BUFFER RESOLUÇÃO') {
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid Industrial de Alta Fidelidade
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=50) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=50) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const drawConveyor = (pts: Point[], col = '#1e293b', w = 34) => {
      // Sombra da Esteira
      ctx.beginPath(); ctx.strokeStyle = 'rgba(0,0,0,0.5)'; ctx.lineWidth = w + 4; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();

      // Base da Esteira
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();

      // Detalhe central (trilho)
      ctx.beginPath(); ctx.strokeStyle = 'rgba(255,255,255,0.03)'; ctx.lineWidth = 2;
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    drawConveyor(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => drawConveyor(b, '#111827', 42));
    drawConveyor(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    drawConveyor(REPAIR_PATH_POINTS, '#1a0505', 38);

    // Render Estações com Glow e Detalhes Técnicos
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Rolo');
      const w = s.width || (isRoll ? 150 : 130), h = s.height || (isRoll ? 70 : 50), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 12 && Math.abs(v.pos.y - s.pos.y) < 12);

      // Glow de atividade
      if (vIn && vIn.waitingTimer > 0) {
        ctx.shadowBlur = 20; ctx.shadowColor = COLORS.SUCCESS + '44';
      }

      ctx.fillStyle = isRoll ? '#010409' : '#0f172a';
      ctx.strokeStyle = vIn && vIn.waitingTimer > 0 ? COLORS.SUCCESS : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 8); ctx.fill(); ctx.stroke();
      ctx.shadowBlur = 0;

      // Marcação Zebra (Segurança) nas bordas
      ctx.fillStyle = '#facc15';
      ctx.fillRect(x, y, 4, h); ctx.fillRect(x + w - 4, y, 4, h);

      ctx.fillStyle = '#e2e8f0'; ctx.font = 'bold 10px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 20);

      if (vIn && vIn.waitingTimer > 0) {
        const p = 1 - (vIn.waitingTimer / s.wait);
        ctx.fillStyle = '#020617'; ctx.fillRect(x + 15, y + 40, w - 30, 8);
        ctx.fillStyle = COLORS.SUCCESS; ctx.fillRect(x + 15, y + 40, (w - 30) * p, 8);

        if (isRoll) {
            ctx.fillStyle = '#6366f1'; ctx.font = '900 9px Inter';
            ctx.fillText(`MODE: ${vIn.rollStep}`, s.pos.x, y + 62);
        }
      } else {
        ctx.fillStyle = '#475569'; ctx.font = 'italic 8px Inter';
        ctx.fillText('STANDBY', s.pos.x, y + 42);
      }
    });

    // Render Veículos com Etiquetas de Status
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);

      // Aura de status
      ctx.shadowBlur = 15; ctx.shadowColor = v.viaVerde ? 'rgba(16, 185, 129, 0.4)' : 'rgba(239, 68, 68, 0.6)';

      ctx.drawImage(vehicleImage.current, -20, -10, 40, 20);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; 
      ctx.beginPath(); ctx.roundRect(-20, -10, 40, 20, 5); ctx.fill();
      ctx.restore();

      // Etiqueta VIN flutuante
      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px "Space Mono"'; ctx.textAlign = 'center';
      ctx.fillText(v.id.toUpperCase(), v.pos.x, v.pos.y - 18);
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const releaseVehicle = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));
      v.targetPath = v.needsH2ORetesting ? [...MAIN_PATH_POINTS].slice(16) : [...MAIN_PATH_POINTS].slice(15);
      v.pathIdx = 0;
      addLog(`GOP SYNC: VIN ${v.id.toUpperCase()} RE-VALIDADO PARA LINHA`);
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      <aside className="w-[440px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="absolute inset-0 bg-gradient-to-b from-indigo-500/5 to-transparent pointer-events-none" />

        <div className="p-10 border-b border-slate-900/50 space-y-8 relative">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="p-3.5 bg-indigo-600 rounded-2xl shadow-indigo-500/30 shadow-2xl ring-1 ring-white/20"><Boxes className="w-6 h-6 text-white" /></div>
              <div>
                <h1 className="text-[14px] font-black tracking-[0.2em] text-white uppercase">VPD Command</h1>
                <p className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">Global Ops Platform</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[10px] font-black uppercase tracking-widest shadow-lg`}>
               <Radio className={`w-3.5 h-3.5 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Live' : 'Stop'}
            </div>
          </div>

          <div className="space-y-5 bg-slate-950/50 p-6 rounded-3xl border border-white/5">
            <div className="flex justify-between items-end">
              <div className="space-y-1">
                <span className="text-[10px] font-black text-slate-700 uppercase tracking-[0.3em]">Production Flow</span>
                <div className="text-5xl font-black text-white tabular-nums tracking-tighter">{stats.produced} <span className="text-slate-800 text-2xl">/ 500</span></div>
              </div>
              <div className="text-right flex flex-col items-end">
                <Monitor className="w-5 h-5 text-indigo-400 mb-2" />
                <span className="text-lg font-black text-indigo-400 tracking-tight">{((stats.produced/500)*100).toFixed(1)}%</span>
              </div>
            </div>
            <div className="h-4 w-full bg-slate-950 rounded-full border border-slate-800 p-1 shadow-inner">
               <div className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full shadow-[0_0_20px_rgba(99,102,241,0.6)] transition-all duration-1000 ease-out" style={{ width: `${(stats.produced/500)*100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/40 p-2 mx-8 my-8 rounded-2xl border border-slate-900/50">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" />, label: 'Analytics' },
            { id: 'QUALITY', icon: <ShieldAlert className="w-4 h-4" />, label: 'Repair' },
            { id: 'NODES', icon: <LayoutGrid className="w-4 h-4" />, label: 'Nodes' }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 flex flex-col items-center gap-2 py-4 rounded-xl transition-all ${activeTab === tab.id ? 'bg-indigo-600/10 text-indigo-400 shadow-lg ring-1 ring-indigo-500/20' : 'text-slate-700 hover:text-slate-500 hover:bg-white/5'}`}>
              {tab.icon}
              <span className="text-[9px] font-black uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-10 pb-10 space-y-12">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <section className="grid grid-cols-2 gap-5">
                <div className="p-6 bg-slate-900/40 border border-slate-900 rounded-[2rem] group hover:border-emerald-500/30 transition-all shadow-xl">
                  <div className="flex items-center gap-3 mb-3">
                    <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-emerald-500/50 shadow-lg" />
                    <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">FTT Score</span>
                  </div>
                  <div className="text-4xl font-black text-emerald-400 tabular-nums">{((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%</div>
                </div>
                <div className="p-6 bg-slate-900/40 border border-slate-900 rounded-[2rem] group hover:border-indigo-500/30 transition-all shadow-xl">
                  <div className="flex items-center gap-3 mb-3">
                    <div className="w-2 h-2 rounded-full bg-indigo-500 shadow-indigo-500/50 shadow-lg" />
                    <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">FTR Index</span>
                  </div>
                  <div className="text-4xl font-black text-indigo-400 tabular-nums">{((stats.ftrSuccesses / (stats.repairCompletedCount || 1)) * 100).toFixed(1)}%</div>
                </div>
              </section>

              <section className="space-y-5">
                <header className="text-[11px] font-black text-slate-700 uppercase tracking-[0.4em] flex items-center gap-3"><Monitor className="w-4 h-4" /> Cabin Occupancy</header>
                <div className="grid grid-cols-3 gap-4">
                  {[0,1,2].map(i => {
                    const occ = vehiclesRef.current.find(v => v.assignedCabinId === PARALLEL_ROLL_STATIONS[i].id);
                    return (
                      <div key={i} className={`p-5 rounded-3xl border flex flex-col items-center gap-3 transition-all ${occ ? 'bg-indigo-500/10 border-indigo-500/40 shadow-2xl shadow-indigo-500/10' : 'bg-slate-900/20 border-slate-900'}`}>
                        <div className={`p-2.5 rounded-xl ${occ ? 'bg-indigo-500 text-white shadow-lg' : 'bg-slate-800 text-slate-700'}`}>
                          <Gauge className="w-5 h-5" />
                        </div>
                        <span className={`text-[9px] font-black uppercase tracking-widest ${occ ? 'text-indigo-400' : 'text-slate-800'}`}>{occ ? occ.rollStep : 'EMPTY'}</span>
                      </div>
                    );
                  })}
                </div>
              </section>

              <section className="p-8 bg-slate-950/80 border border-slate-900 rounded-[2.5rem] space-y-8 shadow-2xl relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-4 opacity-5"><Zap className="w-24 h-24" /></div>
                 <header className="flex justify-between items-center text-[11px] font-black text-slate-700 uppercase tracking-widest relative z-10">
                   <span>Critical Fault Distribution</span>
                   <ActivitySquare className="w-4 h-4" />
                 </header>
                 <div className="space-y-7 relative z-10">
                   {Object.entries(stats.categoryVolumes).map(([cat, val]) => (
                     <div key={cat} className="space-y-3">
                        <div className="flex justify-between text-[10px] font-black uppercase tracking-tight">
                          <span className="text-slate-500">{cat}</span>
                          <span className="text-slate-300">{val} Units</span>
                        </div>
                        <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner">
                           <div className="h-full bg-gradient-to-r from-indigo-500/50 to-indigo-400/50 transition-all duration-1000" style={{ width: `${(val / (stats.defects || 1)) * 100}%` }} />
                        </div>
                     </div>
                   ))}
                 </div>
              </section>
            </div>
          )}

          {activeTab === 'QUALITY' && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <header className="flex justify-between items-center text-[11px] font-black text-slate-600 uppercase tracking-[0.3em] bg-slate-950/80 p-5 rounded-2xl border border-slate-900 shadow-xl">
                <span>Buffer Zone Alpha</span>
                <span className="px-4 py-1.5 bg-rose-500/20 text-rose-500 rounded-full text-[9px] font-black border border-rose-500/20 shadow-lg">{vehiclesRef.current.filter(v=>v.isLocked).length} PENDING</span>
              </header>
              <div className="space-y-6">
                {vehiclesRef.current.filter(v=>v.isLocked).map(v => (
                  <div key={v.id} className="p-8 bg-slate-900/60 border border-slate-800 rounded-[2.5rem] space-y-8 hover:border-indigo-500/40 transition-all group shadow-2xl ring-1 ring-white/5">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-5 rounded shadow-2xl ring-2 ring-white/10" style={{ backgroundColor: v.color }} />
                        <span className="text-[14px] font-black text-white tracking-[0.2em]">{v.id.toUpperCase()}</span>
                      </div>
                      <div className="px-3 py-1 bg-rose-500/10 text-rose-500 font-black text-[10px] uppercase rounded-lg border border-rose-500/20">{v.failureType}</div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 bg-slate-950/80 rounded-2xl border border-slate-900">
                          <span className="text-[9px] font-black text-slate-700 uppercase block mb-2 tracking-widest">H2O Scan</span>
                          <span className={`text-[11px] font-bold tracking-tighter ${v.waterTestStatus === 'FAIL' ? 'text-rose-500' : 'text-slate-500'}`}>{v.waterTestStatus}</span>
                        </div>
                        <div className="p-4 bg-slate-950/80 rounded-2xl border border-slate-900">
                          <span className="text-[9px] font-black text-slate-700 uppercase block mb-2 tracking-widest">Roll Ops</span>
                          <span className="text-[11px] font-bold text-slate-500 tracking-tighter">{v.rollTestStatus}</span>
                        </div>
                    </div>
                    <button onClick={() => releaseVehicle(v.id)} className="w-full py-5 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-black uppercase tracking-[0.3em] rounded-2xl shadow-2xl shadow-indigo-600/20 transition-all active:scale-95 flex items-center justify-center gap-4">
                       <ArrowRight className="w-5 h-5" /> Execute Re-Sync
                    </button>
                  </div>
                ))}
                {vehiclesRef.current.filter(v=>v.isLocked).length === 0 && (
                  <div className="py-32 flex flex-col items-center justify-center opacity-10">
                    <CheckCircle2 className="w-24 h-24 mb-8 text-emerald-500" />
                    <span className="text-[11px] font-black uppercase tracking-[0.8em]">Operations Clean</span>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        <div className="p-10 border-t border-slate-900 bg-slate-950/60 backdrop-blur-xl space-y-5">
          <div className="grid grid-cols-2 gap-5">
            <button onClick={() => setIsRunning(!isRunning)} className={`py-5 rounded-2xl text-[12px] font-black uppercase tracking-[0.2em] transition-all flex justify-center gap-4 items-center shadow-2xl ${isRunning ? 'bg-slate-900 text-slate-600 border border-white/5' : 'bg-indigo-600 text-white shadow-indigo-600/30'}`}>
               {isRunning ? <Pause className="w-5 h-5" /> : <Play className="w-5 h-5" />} {isRunning ? 'Hold' : 'Run'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("GLOBAL RESET EXECUTED"); }} className="py-5 bg-slate-900 text-slate-700 hover:text-rose-500 rounded-2xl text-[12px] font-black uppercase tracking-[0.2em] transition-all flex justify-center gap-4 items-center border border-white/5 shadow-2xl">
              <RotateCcw className="w-5 h-5" /> Reset
            </button>
          </div>
          <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; }); }} className="w-full py-5 bg-indigo-500/5 border border-indigo-500/10 hover:border-indigo-500/30 text-indigo-400 text-[11px] font-black uppercase tracking-[0.3em] rounded-2xl transition-all flex justify-center items-center gap-4 active:scale-95 shadow-2xl">
             <Key className="w-5 h-5" /> Master Release Protocol
          </button>
        </div>
      </aside>

      <main className="flex-1 relative flex flex-col bg-[#01040a]">

        <header className="h-24 border-b border-slate-900/50 flex items-center justify-between px-12 bg-[#020617]/80 backdrop-blur-2xl z-20 shrink-0">
          <div className="flex gap-16">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-[0.4em] mb-2">Live Factory Stream</span>
              <div className="flex items-center gap-4 text-[16px] font-black text-slate-200 tracking-tight">
                <Activity className="w-5 h-5 text-indigo-500" /> Plant_01.Assembly_A
              </div>
            </div>
            <div className="flex flex-col border-l border-slate-900 pl-16">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-[0.4em] mb-2">Process Efficiency</span>
              <div className="flex items-center gap-4 text-[16px] font-black text-emerald-400 tracking-tight">
                <Gauge className="w-5 h-5" /> Optimal_Sync
              </div>
            </div>
          </div>
          <div className="flex items-center gap-6 bg-slate-950 p-3 rounded-2xl border border-white/5 shadow-2xl">
             <div className="px-6 py-3 bg-indigo-500/10 rounded-xl border border-indigo-500/20">
               <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.3em] flex items-center gap-4"><Monitor className="w-4 h-4" /> IIoT_v5.2.0</span>
             </div>
          </div>
        </header>

        <div ref={viewportRef} className="flex-1 flex items-center justify-center relative bg-dot-pattern overflow-hidden p-6">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center center',
              transition: 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)'
            }} 
            className="relative bg-[#020617] rounded-[5rem] shrink-0 overflow-hidden border-2 border-slate-800 shadow-[0_100px_200px_-40px_rgba(0,0,0,1)] flex items-center justify-center group"
          >
            <div className="absolute inset-0 opacity-15 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#334155 2px, transparent 2px)', backgroundSize: '40px 40px' }} />

            <canvas ref={canvasRef} className="relative z-10" />

            <div className="absolute top-20 left-24 opacity-5 pointer-events-none select-none">
              <h2 className="text-[36px] font-black text-slate-700 uppercase tracking-[1.5em]">GOP_PROTOCOL_ALPHA</h2>
            </div>

            <div className="absolute inset-8 border border-white/5 rounded-[4.2rem] pointer-events-none shadow-inner" />
          </div>
        </div>

        <footer className="h-20 bg-[#020617] border-t border-slate-900 flex items-center px-12 gap-12 shrink-0 overflow-hidden text-[10px] font-black uppercase tracking-[0.5em] text-slate-700 z-20">
          <div className="flex items-center gap-4 text-indigo-500 shrink-0 border-r border-slate-900 pr-12 h-full"><Terminal className="w-5 h-5" /> SYSTEM_LOG</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-24 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-4 items-center ${l.includes('ALERTA') ? 'text-rose-500' : 'text-slate-500'}`}>
                  <div className={`w-2 h-2 rounded-full ${l.includes('ALERTA') ? 'bg-rose-500 animate-pulse shadow-lg shadow-rose-500/50' : 'bg-slate-800'}`} /> {l}
                </span>
              ))}
              {logs.length === 0 && <span className="opacity-40 italic tracking-widest">IIoT Stream established... Awaiting data packets...</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 70s linear infinite; }
        .bg-dot-pattern {
          background-image: radial-gradient(rgba(30, 41, 59, 0.25) 1.5px, transparent 1.5px);
          background-size: 50px 50px;
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING',
  PRE_DELIVERY = 'PRE_DELIVERY'
}

export type FailureType = 'ELECTRICAL' | 'ELECTRONIC' | 'MECHANICAL' | 'LEAKAGE';
export type RollFailureType = 'ECATS' | 'VELOCITY';
export type QualityStatus = 'NONE' | 'PASS' | 'FAIL';
export type RollTestStep = 'READY' | 'ECATS' | 'ACCEL' | 'BRAKE' | 'DONE';

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; 
  type: StationType;
  width?: number;
  height?: number;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasDefect: boolean;
  color: string;
  baseColor: string;
  isLocked: boolean;
  failureType: FailureType | null;
  workOrderId: string | null;
  repairStartTime: number | null;
  currentLeadTime: number;

  // Status de Qualidade Avançado
  viaVerde: boolean; // FTT Indicator
  rollTestStatus: QualityStatus;
  waterTestStatus: QualityStatus;
  preDeliveryStatus: QualityStatus;

  // Travas sistêmicas
  needsH2ORetesting: boolean;
  readyForOffloading: boolean;
  inRepair: boolean;
  assignedCabinId: string | null;
  rollStep: RollTestStep;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  totalStarted: number;
  passedFirstTime: number; 
  ftrSuccesses: number;    
  repairCompletedCount: number;
  categoryVolumes: Record<FailureType, number>;
  rollTestProcessed: number;
  ecatsFailures: number;
  velocityFailures: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Search, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Cpu, Boxes, Droplets, ArrowRight, Truck
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType, QualityStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'KPI' | 'REPAIR' | 'OFFLOAD'>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(440); 
  const [speed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 60) / SIM_WIDTH, (rect.height - 60) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.22, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        // Gate: Teste de Rolo
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE') {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        const station = (v.inRepair ? REPAIR_STATIONS : STATIONS)[v.pathIdx] || 
                        PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const moveToRepair = (type: FailureType, source: string) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type;
            v.color = '#ef4444';
            v.targetPath = [...REPAIR_PATH_POINTS]; v.pathIdx = 0;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`REPROVADO: [${v.id}] EM ${source} - MOVENDO PARA REPARO`);
          };

          if (station.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.35) {
              v.rollTestStatus = 'FAIL';
              moveToRepair('ELECTRONIC', 'TESTE DE ROLO');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.15) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              moveToRepair('LEAKAGE', 'TESTE DE ÁGUA');
            } else { 
              v.waterTestStatus = 'PASS'; 
              v.needsH2ORetesting = false;
              addLog(`LOG H2O: [${v.id}] REVALIDADO`);
            }
          }

          // Pre-Delivery Check
          if (station.name === 'EMBARQUE' && v.preDeliveryStatus !== 'PASS') {
             v.waitingTimer = 180; // Simula tempo de Pre-Delivery
             v.preDeliveryStatus = 'PASS';
             v.readyForOffloading = true;
             addLog(`PRE-DELIVERY OK: [${v.id}] STATUS -> OK DESEMBARQUE`);
          }

          if (v.inRepair && station.name === 'Waiting Area') {
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid Visual
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    // Render Estações
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const w = s.width || (isRoll ? 150 : 130), h = s.height || (isRoll ? 64 : 44), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      ctx.fillStyle = isRoll ? '#020617' : '#0f172a';
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? '#10b981' : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();

      ctx.fillStyle = '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 18);

      if (vehicleIn && vehicleIn.waitingTimer > 0) {
        const p = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = '#020617'; ctx.fillRect(x + 10, y + 35, w - 20, 6);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 10, y + 35, (w - 20) * p, 6);
        if (isRoll) {
            ctx.fillStyle = '#6366f1'; ctx.font = '800 8px Inter';
            ctx.fillText(`PROT: ${vehicleIn.rollStep}`, s.pos.x, y + 55);
        }
      }
    });

    // Render Veículos
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 10; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      // Chassi Label
      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px "Space Mono"'; ctx.textAlign = 'center';
      ctx.fillText(v.id, v.pos.x, v.pos.y - 18);
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));

      // Se era vazamento, volta para o teste de água
      if (v.needsH2ORetesting) {
