                </span>
              ))}
              {logs.length === 0 && <span className="opacity-40 italic tracking-widest">IIoT Stream established... Awaiting data packets...</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 70s linear infinite; }
        .bg-dot-pattern {
          background-image: radial-gradient(rgba(30, 41, 59, 0.25) 1.5px, transparent 1.5px);
          background-size: 50px 50px;
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Search, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Cpu, Boxes, Droplets, ArrowRight, Truck, MonitorDot
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType, QualityStatus, StationType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'KPI' | 'REPAIR' | 'OFFLOAD'>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(440); 
  const [speed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 60) / SIM_WIDTH, (rect.height - 60) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.22, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY'
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        // Gate: Teste de Rolo
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE') {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        // Improved Station Detection
        const station = (!v.inRepair ? STATIONS[v.pathIdx] : null) || 
                        Object.values(REPAIR_STATIONS).find(s => v.inRepair && Math.abs(s.pos.x - v.pos.x) < 5 && Math.abs(s.pos.y - v.pos.y) < 5) ||
                        PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (station) {
          v.waitingTimer = station.wait;

          const moveToRepair = (type: FailureType, source: string) => {
            v.viaVerde = false; v.inRepair = true; v.failureType = type;
            v.color = '#ef4444';

            // Fail-specific Routing
            const entry = REPAIR_PATH_POINTS[0];
            const wait = REPAIR_PATH_POINTS[1];
            const mec = REPAIR_PATH_POINTS[2];
            const leak = REPAIR_PATH_POINTS[3];
            const elec = REPAIR_PATH_POINTS[4];
            const ret = REPAIR_PATH_POINTS[5];
            const back = REPAIR_PATH_POINTS[6];

            if (type === 'MECHANICAL') {
                v.targetPath = [entry, mec, ret, back];
            } else if (type === 'LEAKAGE') {
                v.targetPath = [entry, wait, leak, ret, back];
            } else { // ELECTRICAL or ELECTRONIC
                v.targetPath = [entry, wait, elec, ret, back];
            }

            v.pathIdx = 0;
            setStats(s => ({ ...s, defects: s.defects + 1, categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } }));
            addLog(`REPROVADO: [${v.id}] EM ${source} - MOVENDO PARA CELULA ${type}`);
          };

          if (station.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.35) {
              v.rollTestStatus = 'FAIL';
              // Randomly assign electrical vs mechanical failure for rolo
              moveToRepair(Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'TESTE DE ROLO');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (station.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.15) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              moveToRepair('LEAKAGE', 'TESTE DE ÁGUA');
            } else { 
              v.waterTestStatus = 'PASS'; 
              v.needsH2ORetesting = false;
              addLog(`LOG H2O: [${v.id}] REVALIDADO`);
            }
          }

          // Pre-Delivery Check
          if (station.name === 'EMBARQUE' && v.preDeliveryStatus !== 'PASS') {
             v.waitingTimer = 180; // Simula tempo de Pre-Delivery
             v.preDeliveryStatus = 'PASS';
             v.readyForOffloading = true;
             addLog(`PRE-DELIVERY OK: [${v.id}] STATUS -> OK DESEMBARQUE`);
          }

          // Stop and Lock at Repair Station
          if (v.inRepair && station.type === StationType.REPAIR) {
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid Visual
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    // Render Estações
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const w = s.width || (isRoll ? 150 : 130), h = s.height || (isRoll ? 64 : 44), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 10 && Math.abs(v.pos.y - s.pos.y) < 10);

      ctx.fillStyle = isRoll ? '#020617' : '#0f172a';
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? '#10b981' : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();

      ctx.fillStyle = '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 18);

      if (vehicleIn && vehicleIn.waitingTimer > 0) {
        const p = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = '#020617'; ctx.fillRect(x + 10, y + 35, w - 20, 6);
        ctx.fillStyle = '#10b981'; ctx.fillRect(x + 10, y + 35, (w - 20) * p, 6);
        if (isRoll) {
            ctx.fillStyle = '#6366f1'; ctx.font = '800 8px Inter';
            ctx.fillText(`PROT: ${vehicleIn.rollStep}`, s.pos.x, y + 55);
        }
      }
    });

    // Render Veículos
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 10; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      // Chassi Label
      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px "Space Mono"'; ctx.textAlign = 'center';
      ctx.fillText(v.id, v.pos.x, v.pos.y - 18);
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));

      // Se era vazamento, volta para o teste de água
      if (v.needsH2ORetesting) {
        v.targetPath = [...MAIN_PATH_POINTS].slice(16); // Volta para FAI -> Água
        v.pathIdx = 0;
        addLog(`REVALIDAÇÃO H2O: [${v.id}] RETORNANDO AO TESTE DE ÁGUA`);
      } else {
        v.targetPath = [...MAIN_PATH_POINTS].slice(15); // Reparo elétrico/geral volta para FAI
        v.pathIdx = 0;
        addLog(`REPARO CONCLUÍDO: [${v.id}] REINCERIDO NA LINHA`);
      }
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      <aside className="w-[420px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="p-8 border-b border-slate-900/50 space-y-8 bg-gradient-to-b from-indigo-500/5 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-indigo-600 rounded-2xl shadow-indigo-500/30 shadow-2xl ring-1 ring-white/10"><Boxes className="w-6 h-6 text-white" /></div>
              <div>
                <h1 className="text-[12px] font-black tracking-widest text-white uppercase">VPD Command Center</h1>
                <p className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">Alvo: 500 Unidades/Dia</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[9px] font-black uppercase tracking-widest`}>
               <Radio className={`w-3.5 h-3.5 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Line Live' : 'Stopped'}
            </div>
          </div>

          <div className="space-y-4 bg-slate-950/50 p-6 rounded-3xl border border-white/5 shadow-xl">
            <div className="flex justify-between items-end">
              <div className="space-y-1">
                <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Produção Acumulada</span>
                <div className="text-4xl font-black text-white tabular-nums tracking-tighter">{stats.produced} <span className="text-slate-800 text-xl">/ 500</span></div>
              </div>
              <div className="text-right flex flex-col items-end">
                <MonitorDot className="w-5 h-5 text-indigo-400 mb-2" />
                <span className="text-sm font-black text-indigo-400 tracking-tight">{((stats.produced/500)*100).toFixed(1)}%</span>
              </div>
            </div>
            <div className="h-3 w-full bg-slate-950 rounded-full border border-slate-900 p-0.5 shadow-inner">
               <div className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.5)] transition-all duration-1000" style={{ width: `${(stats.produced/500)*100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/40 p-2 mx-8 my-6 rounded-2xl border border-slate-900">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" />, label: 'Analytics' },
            { id: 'REPAIR', icon: <ShieldAlert className="w-4 h-4" />, label: 'Reparo' },
            { id: 'OFFLOAD', icon: <Truck className="w-4 h-4" />, label: 'Desembarque' }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 flex flex-col items-center gap-2 py-4 rounded-xl transition-all ${activeTab === tab.id ? 'bg-indigo-600/10 text-indigo-400 shadow-inner' : 'text-slate-700 hover:text-slate-500'}`}>
              {tab.icon}
              <span className="text-[9px] font-black uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-10 pb-10 space-y-10">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <section className="grid grid-cols-2 gap-4">
                <div className="p-6 bg-slate-900/40 border border-slate-900 rounded-[2rem] group hover:border-emerald-500/20 transition-all shadow-xl">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-emerald-500" /> FTT Rate</span>
                  <div className="text-3xl font-black text-emerald-400 mt-2">{((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%</div>
                </div>
                <div className="p-6 bg-slate-900/40 border border-slate-900 rounded-[2rem] group hover:border-indigo-500/20 transition-all shadow-xl">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-indigo-500" /> FTR Index</span>
                  <div className="text-3xl font-black text-indigo-400 mt-2">{((stats.ftrSuccesses / (stats.repairCompletedCount || 1)) * 100).toFixed(1)}%</div>
                </div>
              </section>

              <section className="space-y-5 bg-slate-950/80 border border-slate-900 rounded-[2rem] p-6 shadow-2xl relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-4 opacity-5"><Zap className="w-20 h-20 text-indigo-500" /></div>
                 <header className="flex justify-between items-center text-[11px] font-black text-slate-700 uppercase tracking-widest">
                   <span>Falhas por Categoria</span>
                   <ActivitySquare className="w-4 h-4" />
                 </header>
                 <div className="space-y-6 relative z-10">
                   {Object.entries(stats.categoryVolumes).map(([cat, val]) => (
                     <div key={cat} className="space-y-2">
                        <div className="flex justify-between text-[10px] font-black uppercase tracking-tight">
                          <span className="text-slate-500">{cat}</span>
                          <span className="text-slate-300">{val}</span>
                        </div>
                        <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner">
                           <div className="h-full bg-indigo-500/50 transition-all duration-1000" style={{ width: `${(val / (stats.defects || 1)) * 100}%` }} />
                        </div>
                     </div>
                   ))}
                 </div>
              </section>
            </div>
          )}

          {activeTab === 'REPAIR' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <header className="flex justify-between items-center text-[10px] font-black text-slate-600 uppercase tracking-widest bg-slate-950/80 p-5 rounded-2xl border border-slate-900 shadow-xl">
                <span>Buffer de Resolução</span>
                <span className="px-3 py-1 bg-rose-500/20 text-rose-500 rounded-full text-[9px] font-black border border-rose-500/20">{vehiclesRef.current.filter(v=>v.isLocked).length} UNIDADES</span>
              </header>
              <div className="space-y-4">
                {vehiclesRef.current.filter(v=>v.isLocked).map(v => (
                  <div key={v.id} className="p-6 bg-slate-900/60 border border-slate-800 rounded-[2rem] space-y-6 hover:border-indigo-500/40 transition-all group shadow-2xl">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-5 rounded shadow-2xl ring-1 ring-white/10" style={{ backgroundColor: v.color }} />
                        <span className="text-[14px] font-black text-white tracking-widest">{v.id}</span>
                      </div>
                      <div className="px-2.5 py-1 bg-rose-500/10 text-rose-500 font-black text-[10px] uppercase rounded-lg border border-rose-500/20">{v.failureType}</div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 bg-slate-950/80 rounded-2xl border border-slate-900">
                          <span className="text-[9px] font-black text-slate-700 uppercase block mb-2">H2O Log</span>
                          <span className={`text-[10px] font-bold ${v.waterTestStatus === 'FAIL' ? 'text-rose-500' : 'text-slate-500'}`}>{v.waterTestStatus}</span>
                        </div>
                        <div className="p-4 bg-slate-950/80 rounded-2xl border border-slate-900">
                          <span className="text-[9px] font-black text-slate-700 uppercase block mb-2">Roll Log</span>
                          <span className="text-[10px] font-bold text-slate-500">{v.rollTestStatus}</span>
                        </div>
                    </div>
                    <button onClick={() => validateRepair(v.id)} className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white text-[11px] font-black uppercase tracking-[0.2em] rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3">
                       <ArrowRight className="w-5 h-5" /> Validar & Liberar
                    </button>
                  </div>
                ))}
                {vehiclesRef.current.filter(v=>v.isLocked).length === 0 && (
                  <div className="py-24 flex flex-col items-center justify-center opacity-10">
                    <CheckCircle2 className="w-20 h-20 mb-6 text-emerald-500" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em]">Operação Sincronizada</span>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'OFFLOAD' && (
            <div className="space-y-6 animate-in fade-in duration-500">
