const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'KPI' | 'REPAIR' | 'OFFLOAD'>('KPI');
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(440); 
  const [speed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 60) / SIM_WIDTH, (rect.height - 60) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.22, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY',
      hasPassedFAI: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const moveToRepair = (v: Vehicle, type: FailureType, source: string) => {
    v.viaVerde = false; v.inRepair = true; v.failureType = type;
    v.color = '#ef4444';

    // specialized Pathing
    const entry = REPAIR_PATH_POINTS[0];
    const junction = REPAIR_PATH_POINTS[1];
    const mecCell = REPAIR_PATH_POINTS[2];
    const leakCell = REPAIR_PATH_POINTS[3];
    const elecCell = REPAIR_PATH_POINTS[4];
    const returnPath = REPAIR_PATH_POINTS[5];
    const exitPath = REPAIR_PATH_POINTS[6];

    if (type === 'MECHANICAL') {
        v.targetPath = [entry, junction, mecCell, returnPath, exitPath];
    } else if (type === 'LEAKAGE') {
        v.targetPath = [entry, junction, leakCell, returnPath, exitPath];
    } else { // ELECTRICAL or ELECTRONIC
        v.targetPath = [entry, junction, elecCell, returnPath, exitPath];
    }

    v.pathIdx = 0;
    setStats(s => ({ 
      ...s, 
      defects: s.defects + 1, 
      categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } 
    }));
    addLog(`FAIL: [${v.id}] @ ${source} -> DISPATCHED TO ${type} CELL`);
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        // Regra de Negócio: Se passou pelo FAI, ignora o desvio para o Teste de Rolo
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE' && !v.hasPassedFAI) {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        const currentStation = (!v.inRepair ? STATIONS[v.pathIdx] : null) || 
                               Object.values(REPAIR_STATIONS).find(s => v.inRepair && Math.abs(s.pos.x - v.pos.x) < 8 && Math.abs(s.pos.y - v.pos.y) < 8) ||
                               PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (currentStation) {
          v.waitingTimer = currentStation.wait;

          if (currentStation.name === 'FAI QC') {
            v.hasPassedFAI = true;
            addLog(`QUALITY GATE: [${v.id}] CLEARED FAI - ROLL TEST BYPASS ACTIVE`);
          }

          if (currentStation.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.35) {
              v.rollTestStatus = 'FAIL';
              moveToRepair(v, Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLL TEST');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (currentStation.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.15) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              moveToRepair(v, 'LEAKAGE', 'H2O TEST');
            } else { 
              v.waterTestStatus = 'PASS'; 
              v.needsH2ORetesting = false;
            }
          }

          if (currentStation.name === 'EMBARQUE' && v.preDeliveryStatus !== 'PASS') {
             v.waitingTimer = 180;
             v.preDeliveryStatus = 'PASS';
             v.readyForOffloading = true;
             addLog(`SHIPPING OK: [${v.id}] READY FOR OFFLOAD`);
          }

          // Auto-lock only at the assigned specialized repair station
          if (v.inRepair && currentStation.type === StationType.REPAIR) {
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    // Grid Visual
    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    // Render Stations
    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const isRepair = s.type === StationType.REPAIR;
      const w = s.width || (isRoll ? 150 : 130), h = s.height || (isRoll ? 64 : 44), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 12 && Math.abs(v.pos.y - s.pos.y) < 12);

      ctx.fillStyle = isRoll ? '#020617' : (isRepair ? '#1a0505' : '#0f172a');
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? '#10b981' : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();

      ctx.fillStyle = isRepair ? '#fca5a5' : '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 18);

      if (vehicleIn && vehicleIn.waitingTimer > 0) {
        const p = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = '#020617'; ctx.fillRect(x + 10, y + 35, w - 20, 6);
        ctx.fillStyle = isRepair ? '#ef4444' : '#10b981'; ctx.fillRect(x + 10, y + 35, (w - 20) * p, 6);
      }
    });

    // Render Vehicles
    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 10; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px "Space Mono"'; ctx.textAlign = 'center';
      ctx.fillText(v.id, v.pos.x, v.pos.y - 18);

      // Indicator for FAI cleared
      if (v.hasPassedFAI) {
        ctx.fillStyle = '#10b981';
        ctx.beginPath();
        ctx.arc(v.pos.x + 22, v.pos.y - 10, 4, 0, Math.PI * 2);
        ctx.fill();
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));

      if (v.needsH2ORetesting) {
        // Se já passou pelo FAI antes do vazamento, volta direto para o Teste de Água, pulando FAI
        v.targetPath = [...MAIN_PATH_POINTS].slice(16);
        v.pathIdx = 0;
        addLog(`RE-VALIDATE: [${v.id}] RETURNING TO H2O CHAMBER`);
      } else {
        // Volta para a linha principal após o reparo (ponto de re-entrada no Reparo Elétrico)
        v.targetPath = [...MAIN_PATH_POINTS].slice(15);
        v.pathIdx = 0;
        addLog(`REPAIRED: [${v.id}] RE-INTEGRATED TO MAIN LINE`);
      }
    }
  };

  const getRepairIcon = (type: string | null) => {
    switch(type) {
      case 'MECHANICAL': return <Wrench className="w-4 h-4" />;
      case 'LEAKAGE': return <WaterIcon className="w-4 h-4" />;
      case 'ELECTRICAL':
      case 'ELECTRONIC': return <ZapOff className="w-4 h-4" />;
      default: return <ShieldAlert className="w-4 h-4" />;
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      <aside className="w-[420px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="p-8 border-b border-slate-900/50 space-y-8 bg-gradient-to-b from-indigo-500/5 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-indigo-600 rounded-2xl shadow-indigo-500/30 shadow-2xl ring-1 ring-white/10"><Boxes className="w-6 h-6 text-white" /></div>
              <div>
                <h1 className="text-[12px] font-black tracking-widest text-white uppercase">VPD Command Center</h1>
                <p className="text-[9px] font-bold text-slate-600 uppercase tracking-widest">Target: 500 VPD</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[9px] font-black uppercase tracking-widest`}>
               <Radio className={`w-3.5 h-3.5 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Live' : 'Stopped'}
            </div>
          </div>

          <div className="space-y-4 bg-slate-950/50 p-6 rounded-3xl border border-white/5 shadow-xl">
            <div className="flex justify-between items-end">
              <div className="space-y-1">
                <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">Shift Output</span>
                <div className="text-4xl font-black text-white tabular-nums tracking-tighter">{stats.produced} <span className="text-slate-800 text-xl">/ 500</span></div>
              </div>
              <div className="text-right flex flex-col items-end">
                <MonitorDot className="w-5 h-5 text-indigo-400 mb-2" />
                <span className="text-sm font-black text-indigo-400 tracking-tight">{((stats.produced/500)*100).toFixed(1)}%</span>
              </div>
            </div>
            <div className="h-3 w-full bg-slate-950 rounded-full border border-slate-900 p-0.5 shadow-inner">
               <div className="h-full bg-gradient-to-r from-indigo-600 to-indigo-400 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.5)] transition-all duration-1000" style={{ width: `${(stats.produced/500)*100}%` }} />
            </div>
          </div>
        </div>

        <nav className="flex bg-slate-950/40 p-2 mx-8 my-6 rounded-2xl border border-slate-900">
          {[
            { id: 'KPI', icon: <BarChart className="w-4 h-4" />, label: 'Stats' },
            { id: 'REPAIR', icon: <ShieldAlert className="w-4 h-4" />, label: 'Repair' },
            { id: 'OFFLOAD', icon: <Truck className="w-4 h-4" />, label: 'Shipping' }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 flex flex-col items-center gap-2 py-4 rounded-xl transition-all ${activeTab === tab.id ? 'bg-indigo-600/10 text-indigo-400 shadow-inner' : 'text-slate-700 hover:text-slate-500'}`}>
              {tab.icon}
              <span className="text-[9px] font-black uppercase tracking-widest">{tab.label}</span>
            </button>
          ))}
        </nav>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-10 pb-10 space-y-10">
          {activeTab === 'KPI' && (
            <div className="space-y-10 animate-in fade-in duration-500">
              <section className="grid grid-cols-2 gap-4">
                <div className="p-6 bg-slate-900/40 border border-slate-900 rounded-[2rem] group hover:border-emerald-500/20 transition-all shadow-xl">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-emerald-500" /> FTT Score</span>
                  <div className="text-3xl font-black text-emerald-400 mt-2">{((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%</div>
                </div>
                <div className="p-6 bg-slate-900/40 border border-slate-900 rounded-[2rem] group hover:border-indigo-500/20 transition-all shadow-xl">
                  <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-indigo-500" /> FTR Index</span>
                  <div className="text-3xl font-black text-indigo-400 mt-2">{((stats.ftrSuccesses / (stats.repairCompletedCount || 1)) * 100).toFixed(1)}%</div>
                </div>
              </section>

              <section className="space-y-5 bg-slate-950/80 border border-slate-900 rounded-[2rem] p-6 shadow-2xl relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-4 opacity-5"><Zap className="w-20 h-20 text-indigo-500" /></div>
                 <header className="flex justify-between items-center text-[11px] font-black text-slate-700 uppercase tracking-widest">
                   <span>Defect Distribution</span>
                   <ActivitySquare className="w-4 h-4" />
                 </header>
                 <div className="space-y-6 relative z-10">
                   {Object.entries(stats.categoryVolumes).map(([cat, val]) => (
                     <div key={cat} className="space-y-2">
                        <div className="flex justify-between text-[10px] font-black uppercase tracking-tight">
                          <span className="text-slate-500">{cat}</span>
                          <span className="text-slate-300">{val} Units</span>
                        </div>
                        <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden shadow-inner">
                           <div className="h-full bg-indigo-500/50 transition-all duration-1000" style={{ width: `${(val / (stats.defects || 1)) * 100}%` }} />
                        </div>
                     </div>
                   ))}
                 </div>
              </section>
            </div>
          )}

          {activeTab === 'REPAIR' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <header className="flex justify-between items-center text-[10px] font-black text-slate-600 uppercase tracking-widest bg-slate-950/80 p-5 rounded-2xl border border-slate-900 shadow-xl">
                <span>Specialized Repair Cells</span>
                <span className="px-3 py-1 bg-rose-500/20 text-rose-500 rounded-full text-[9px] font-black border border-rose-500/20">{vehiclesRef.current.filter(v=>v.inRepair).length} UNITS ACTIVE</span>
              </header>
              <div className="space-y-4">
                {vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                  <div key={v.id} className={`p-6 bg-slate-900/60 border ${v.isLocked ? 'border-rose-500/40 shadow-[0_0_20px_rgba(239,68,68,0.1)]' : 'border-slate-800'} rounded-[2rem] space-y-6 transition-all group shadow-2xl`}>
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-5 rounded shadow-2xl ring-1 ring-white/10" style={{ backgroundColor: v.color }} />
                        <span className="text-[14px] font-black text-white tracking-widest">{v.id}</span>
                      </div>
                      <div className="flex items-center gap-2 px-2.5 py-1 bg-rose-500/10 text-rose-500 font-black text-[9px] uppercase rounded-lg border border-rose-500/20">
                        {getRepairIcon(v.failureType)}
                        {v.failureType}
                      </div>
                    </div>

                    <div className="space-y-1">
                        <div className="flex justify-between text-[8px] font-black text-slate-600 uppercase tracking-widest">
                            <span>Target Station</span>
                            <span>Status</span>
                        </div>
                        <div className="flex justify-between items-center p-3 bg-slate-950/80 rounded-xl border border-slate-900">
                            <span className="text-[10px] font-bold text-indigo-400">
                                {REPAIR_STATIONS[v.failureType!]?.name || 'ASSIGNING...'}
                            </span>
                            <span className={`text-[10px] font-black ${v.isLocked ? 'text-rose-500' : 'text-slate-600'}`}>
                                {v.isLocked ? 'AT CELL' : 'EN ROUTE'}
                            </span>
                        </div>
                    </div>

                    {v.hasPassedFAI && (
                      <div className="flex items-center gap-2 text-[9px] font-black text-emerald-500 bg-emerald-500/10 p-2 rounded-lg border border-emerald-500/20 uppercase tracking-tighter">
                        <ShieldCheck className="w-3.5 h-3.5" /> FAI Cleared - Direct Flow Enabled
                      </div>
                    )}

                    <button 
                        disabled={!v.isLocked}
                        onClick={() => validateRepair(v.id)} 
                        className={`w-full py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${
                            v.isLocked 
                            ? 'bg-indigo-600 hover:bg-indigo-500 text-white' 
                            : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
                        }`}
                    >
                       <ArrowRight className="w-5 h-5" /> 
                       {v.isLocked ? 'Complete & Release' : 'Awaiting Arrival'}
                    </button>
                  </div>
                ))}
                {vehiclesRef.current.filter(v=>v.inRepair).length === 0 && (
                  <div className="py-24 flex flex-col items-center justify-center opacity-10">
                    <CheckCircle2 className="w-20 h-20 mb-6 text-emerald-500" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em]">Cells Nominal</span>
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'OFFLOAD' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <header className="flex justify-between items-center text-[10px] font-black text-slate-600 uppercase tracking-widest bg-slate-950/80 p-5 rounded-2xl border border-slate-900 shadow-xl">
                <span>Shipping Dock</span>
                <span className="px-3 py-1 bg-indigo-500/20 text-indigo-500 rounded-full text-[9px] font-black border border-indigo-500/20">{vehiclesRef.current.filter(v=>v.readyForOffloading).length} UNITS</span>
              </header>
              <div className="space-y-3">
                {vehiclesRef.current.filter(v=>v.readyForOffloading).map(v => (
                  <div key={v.id} className="p-5 bg-slate-900/30 border border-slate-900 rounded-2xl flex items-center justify-between group">
                    <div className="flex items-center gap-4">
                       <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-emerald-500/50 shadow-lg" />
                       <span className="text-xs font-black text-slate-200 tracking-widest">{v.id}</span>
                    </div>
                    <span className="text-[9px] font-black text-emerald-500 uppercase tracking-widest px-3 py-1 bg-emerald-500/10 rounded-lg">OK DESEMBARQUE</span>
                  </div>
                ))}
                {vehiclesRef.current.filter(v=>v.readyForOffloading).length === 0 && (
                  <div className="py-24 flex flex-col items-center justify-center opacity-10">
                    <Truck className="w-20 h-20 mb-6 text-slate-500" />
                    <span className="text-[10px] font-black uppercase tracking-[0.5em]">Awaiting Cargo</span>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>

        <div className="p-8 border-t border-slate-900 bg-slate-950/60 backdrop-blur-xl space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => setIsRunning(!isRunning)} className={`py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center shadow-xl ${isRunning ? 'bg-slate-900 text-slate-600 border border-white/5' : 'bg-indigo-600 text-white shadow-indigo-600/30'}`}>
               {isRunning ? <Pause className="w-5 h-5" /> : <Play className="w-5 h-5" />} {isRunning ? 'Hold' : 'Resume'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setStats({produced:0,defects:0,active:0,totalStarted:0,passedFirstTime:0,ftrSuccesses:0,repairCompletedCount:0,categoryVolumes:{ELECTRICAL:0,ELECTRONIC:0,MECHANICAL:0,LEAKAGE:0},rollTestProcessed:0,ecatsFailures:0,velocityFailures:0}); addLog("GLOBAL RESET: NEW SHIFT"); }} className="py-4 bg-slate-900 text-slate-700 hover:text-rose-500 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all flex justify-center gap-3 items-center border border-white/5 shadow-xl">
              <RotateCcw className="w-5 h-5" /> Reset
            </button>
          </div>
          <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; }); }} className="w-full py-4 bg-indigo-500/5 border border-indigo-500/10 hover:border-indigo-500/30 text-indigo-400 text-[10px] font-black uppercase tracking-widest rounded-2xl transition-all flex justify-center items-center gap-4 active:scale-95 shadow-xl">
             <Key className="w-5 h-5" /> System Overide
          </button>
        </div>
      </aside>

      <main className="flex-1 relative flex flex-col bg-[#01040a]">

        <header className="h-24 border-b border-slate-900/50 flex items-center justify-between px-12 bg-[#020617]/80 backdrop-blur-2xl z-20 shrink-0">
          <div className="flex gap-16">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-[0.4em] mb-2">Live Factory Stream</span>
              <div className="flex items-center gap-4 text-[16px] font-black text-slate-200 tracking-tight">
                <Activity className="w-5 h-5 text-indigo-500" /> Plant_01.Assembly_A
              </div>
            </div>
            <div className="flex flex-col border-l border-slate-900 pl-16">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-[0.4em] mb-2">Process Efficiency</span>
              <div className="flex items-center gap-4 text-[16px] font-black text-emerald-400 tracking-tight">
                <Gauge className="w-5 h-5" /> Optimal_Sync
              </div>
            </div>
          </div>
          <div className="flex items-center gap-6 bg-slate-950 p-3 rounded-2xl border border-white/5 shadow-2xl">
             <div className="px-6 py-3 bg-indigo-500/10 rounded-xl border border-indigo-500/20">
               <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.3em] flex items-center gap-4"><Boxes className="w-4 h-4" /> IIoT_v5.2.0</span>
             </div>
          </div>
        </header>

        <div ref={viewportRef} className="flex-1 flex items-center justify-center relative bg-dot-pattern overflow-hidden p-6">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center center',
              transition: 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)'
            }} 
            className="relative bg-[#020617] rounded-[5rem] shrink-0 overflow-hidden border-2 border-slate-800 shadow-[0_100px_200px_-40px_rgba(0,0,0,1)] flex items-center justify-center group"
          >
            <div className="absolute inset-0 opacity-15 pointer-events-none" style={{ backgroundImage: 'radial-gradient(#334155 2px, transparent 2px)', backgroundSize: '40px 40px' }} />

            <canvas ref={canvasRef} className="relative z-10" />

            <div className="absolute top-20 left-24 opacity-5 pointer-events-none select-none">
              <h2 className="text-[36px] font-black text-slate-700 uppercase tracking-[1.5em]">GOP_PROTOCOL_ALPHA</h2>
            </div>

            <div className="absolute inset-8 border border-white/5 rounded-[4.2rem] pointer-events-none shadow-inner" />
          </div>
        </div>

        <footer className="h-20 bg-[#020617] border-t border-slate-900 flex items-center px-12 gap-12 shrink-0 overflow-hidden text-[10px] font-black uppercase tracking-[0.5em] text-slate-700 z-20">
          <div className="flex items-center gap-4 text-indigo-500 shrink-0 border-r border-slate-900 pr-12 h-full"><Terminal className="w-5 h-5" /> SYSTEM_LOG</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-24 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-4 items-center ${l.includes('REPROVADO') || l.includes('FAIL') ? 'text-rose-500' : 'text-slate-500'}`}>
                  <div className={`w-2 h-2 rounded-full ${l.includes('REPROVADO') || l.includes('FAIL') ? 'bg-rose-500 animate-pulse shadow-lg shadow-rose-500/50' : 'bg-slate-800'}`} /> {l}
                </span>
              ))}
              {logs.length === 0 && <span className="opacity-40 italic tracking-widest">IIoT Stream established... Awaiting data packets...</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 70s linear infinite; }
        .bg-dot-pattern {
          background-image: radial-gradient(rgba(30, 41, 59, 0.25) 1.5px, transparent 1.5px);
          background-size: 50px 50px;
        }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Boxes, ArrowRight, Truck, MonitorDot, Wrench, ZapOff, Droplets as WaterIcon,
  ShieldCheck, TrendingUp, History, ListFilter, ChevronDown
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType, QualityStatus, StationType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(440); 
  const [speed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const dashboardRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  // Refs para navegação de scroll
  const sectionRefs = {
    stats: useRef<HTMLElement>(null),
    repair: useRef<HTMLElement>(null),
    shipping: useRef<HTMLElement>(null)
  };

  const scrollToSection = (section: keyof typeof sectionRefs) => {
    sectionRefs[section].current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 60) / SIM_WIDTH, (rect.height - 60) / SIM_HEIGHT);
    setScale(Math.max(0.1, s));
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    setTimeout(updateScale, 100);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => window.removeEventListener('resize', updateScale);
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.22, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY',
      hasPassedFAI: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const moveToRepair = (v: Vehicle, type: FailureType, source: string) => {
    v.viaVerde = false; v.inRepair = true; v.failureType = type;
    v.color = '#ef4444';

    const entry = REPAIR_PATH_POINTS[0];
    const junction = REPAIR_PATH_POINTS[1];
    const mecCell = REPAIR_PATH_POINTS[2];
    const leakCell = REPAIR_PATH_POINTS[3];
    const elecCell = REPAIR_PATH_POINTS[4];
    const returnPath = REPAIR_PATH_POINTS[5];
    const exitPath = REPAIR_PATH_POINTS[6];

    if (type === 'MECHANICAL') {
        v.targetPath = [entry, junction, mecCell, returnPath, exitPath];
    } else if (type === 'LEAKAGE') {
        v.targetPath = [entry, junction, leakCell, returnPath, exitPath];
    } else { 
        v.targetPath = [entry, junction, elecCell, returnPath, exitPath];
    }

    v.pathIdx = 0;
    setStats(s => ({ 
      ...s, 
      defects: s.defects + 1, 
      categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } 
    }));
    addLog(`FAIL: [${v.id}] @ ${source} -> DISPATCHED TO ${type} CELL`);
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE' && !v.hasPassedFAI) {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        const currentStation = (!v.inRepair ? STATIONS[v.pathIdx] : null) || 
                               Object.values(REPAIR_STATIONS).find(s => v.inRepair && Math.abs(s.pos.x - v.pos.x) < 8 && Math.abs(s.pos.y - v.pos.y) < 8) ||
                               PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (currentStation) {
          v.waitingTimer = currentStation.wait;

          if (currentStation.name === 'FAI QC') {
            v.hasPassedFAI = true;
            addLog(`QUALITY GATE: [${v.id}] CLEARED FAI - ROLL TEST BYPASS ACTIVE`);
          }

          if (currentStation.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.35) {
              v.rollTestStatus = 'FAIL';
              moveToRepair(v, Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLL TEST');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (currentStation.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.15) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              moveToRepair(v, 'LEAKAGE', 'H2O TEST');
            } else { 
              v.waterTestStatus = 'PASS'; 
              v.needsH2ORetesting = false;
            }
          }

          if (currentStation.name === 'EMBARQUE' && v.preDeliveryStatus !== 'PASS') {
             v.waitingTimer = 180;
             v.preDeliveryStatus = 'PASS';
             v.readyForOffloading = true;
             addLog(`SHIPPING OK: [${v.id}] READY FOR OFFLOAD`);
          }

          if (v.inRepair && currentStation.type === StationType.REPAIR) {
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const isRepair = s.type === StationType.REPAIR;
      const w = s.width || (isRoll ? 150 : 130), h = s.height || (isRoll ? 64 : 44), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 12 && Math.abs(v.pos.y - s.pos.y) < 12);

      ctx.fillStyle = isRoll ? '#020617' : (isRepair ? '#1a0505' : '#0f172a');
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? '#10b981' : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();

      ctx.fillStyle = isRepair ? '#fca5a5' : '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 18);

      if (vehicleIn && vehicleIn.waitingTimer > 0) {
        const p = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = '#020617'; ctx.fillRect(x + 10, y + 35, w - 20, 6);
        ctx.fillStyle = isRepair ? '#ef4444' : '#10b981'; ctx.fillRect(x + 10, y + 35, (w - 20) * p, 6);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 10; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px "Space Mono"'; ctx.textAlign = 'center';
      ctx.fillText(v.id, v.pos.x, v.pos.y - 18);

      if (v.hasPassedFAI) {
        ctx.fillStyle = '#10b981';
        ctx.beginPath(); ctx.arc(v.pos.x + 22, v.pos.y - 10, 4, 0, Math.PI * 2); ctx.fill();
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));

      if (v.needsH2ORetesting) {
        v.targetPath = [...MAIN_PATH_POINTS].slice(16);
        v.pathIdx = 0;
        addLog(`RE-VALIDATE: [${v.id}] RETURNING TO H2O CHAMBER`);
      } else {
        v.targetPath = [...MAIN_PATH_POINTS].slice(15);
        v.pathIdx = 0;
        addLog(`REPAIRED: [${v.id}] RE-INTEGRATED TO MAIN LINE`);
      }
    }
  };

  const getRepairIcon = (type: string | null) => {
    switch(type) {
      case 'MECHANICAL': return <Wrench className="w-4 h-4" />;
      case 'LEAKAGE': return <WaterIcon className="w-4 h-4" />;
      case 'ELECTRICAL':
      case 'ELECTRONIC': return <ZapOff className="w-4 h-4" />;
      default: return <ShieldAlert className="w-4 h-4" />;
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      {/* SIDEBAR DASHBOARD - HIGH FIDELITY */}
      <aside className="w-[450px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">

        {/* FIXED HEADER: OUTPUT KPI */}
        <div className="p-8 border-b border-slate-900/50 bg-slate-950/50 backdrop-blur-md">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-indigo-600 rounded-2xl shadow-[0_0_20px_rgba(79,70,229,0.3)] ring-1 ring-white/10"><Boxes className="w-6 h-6 text-white" /></div>
              <div>
                <h1 className="text-[14px] font-black tracking-widest text-white uppercase">GOP Dashboard</h1>
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">IIoT Live Monitoring</p>
              </div>
            </div>
            <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[9px] font-black uppercase tracking-widest`}>
