import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Boxes, ArrowRight, Truck, MonitorDot, Wrench, ZapOff, Droplets as WaterIcon,
  ShieldCheck, TrendingUp, History, ListFilter, Maximize, Minimize
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, RollFailureType, QualityStatus, StationType } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate] = useState(440); 
  const [speed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, ecatsFailures: 0, velocityFailures: 0
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const dashboardRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  // Refs para navegação de scroll
  const sectionRefs = {
    stats: useRef<HTMLElement>(null),
    repair: useRef<HTMLElement>(null),
    shipping: useRef<HTMLElement>(null)
  };

  const scrollToSection = (section: keyof typeof sectionRefs) => {
    sectionRefs[section].current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    // Aumentamos o aproveitamento da tela de 60px de margem para apenas 20px
    const s = Math.min((rect.width - 20) / SIM_WIDTH, (rect.height - 20) / SIM_HEIGHT);
    setScale(s);

    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    // Timeout para garantir que o layout carregou
    const timer = setTimeout(updateScale, 150);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => {
      window.removeEventListener('resize', updateScale);
      clearTimeout(timer);
    };
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const spawnVehicle = useCallback(() => {
    const id = Math.random().toString(36).substr(2, 6).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.22, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, workOrderId: null, repairStartTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY',
      hasPassedFAI: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const moveToRepair = (v: Vehicle, type: FailureType, source: string) => {
    v.viaVerde = false; v.inRepair = true; v.failureType = type;
    v.color = '#ef4444';

    const entry = REPAIR_PATH_POINTS[0];
    const junction = REPAIR_PATH_POINTS[1];
    const mecCell = REPAIR_PATH_POINTS[2];
    const leakCell = REPAIR_PATH_POINTS[3];
    const elecCell = REPAIR_PATH_POINTS[4];
    const returnPath = REPAIR_PATH_POINTS[5];
    const exitPath = REPAIR_PATH_POINTS[6];

    if (type === 'MECHANICAL') {
        v.targetPath = [entry, junction, mecCell, returnPath, exitPath];
    } else if (type === 'LEAKAGE') {
        v.targetPath = [entry, junction, leakCell, returnPath, exitPath];
    } else { 
        v.targetPath = [entry, junction, elecCell, returnPath, exitPath];
    }

    v.pathIdx = 0;
    setStats(s => ({ 
      ...s, 
      defects: s.defects + 1, 
      categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } 
    }));
    addLog(`FAIL: [${v.id}] @ ${source} -> DISPATCHED TO ${type} CELL`);
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;
    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        if (v.assignedCabinId) {
          const cabin = PARALLEL_ROLL_STATIONS.find(ps => ps.id === v.assignedCabinId);
          if (cabin) {
            const prog = 1 - (v.waitingTimer / cabin.wait);
            if (prog < 0.33) v.rollStep = 'ECATS';
            else if (prog < 0.66) v.rollStep = 'ACCEL';
            else v.rollStep = 'BRAKE';
          }
        }
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);
      if (dist < speed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE' && !v.hasPassedFAI) {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null; v.rollStep = 'DONE';
        }

        const currentStation = (!v.inRepair ? STATIONS[v.pathIdx] : null) || 
                               Object.values(REPAIR_STATIONS).find(s => v.inRepair && Math.abs(s.pos.x - v.pos.x) < 8 && Math.abs(s.pos.y - v.pos.y) < 8) ||
                               PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (currentStation) {
          v.waitingTimer = currentStation.wait;

          if (currentStation.name === 'FAI QC') {
            v.hasPassedFAI = true;
            addLog(`QUALITY GATE: [${v.id}] CLEARED FAI - ROLL TEST BYPASS ACTIVE`);
          }

          if (currentStation.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.35) {
              v.rollTestStatus = 'FAIL';
              moveToRepair(v, Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLL TEST');
            } else { v.rollTestStatus = 'PASS'; setStats(s => ({ ...s, rollTestProcessed: s.rollTestProcessed + 1 })); }
          }

          if (currentStation.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.15) {
              v.waterTestStatus = 'FAIL'; v.needsH2ORetesting = true;
              moveToRepair(v, 'LEAKAGE', 'H2O TEST');
            } else { 
              v.waterTestStatus = 'PASS'; 
              v.needsH2ORetesting = false;
            }
          }

          if (currentStation.name === 'EMBARQUE' && v.preDeliveryStatus !== 'PASS') {
             v.waitingTimer = 180;
             v.preDeliveryStatus = 'PASS';
             v.readyForOffloading = true;
             addLog(`SHIPPING OK: [${v.id}] READY FOR OFFLOAD`);
          }

          if (v.inRepair && currentStation.type === StationType.REPAIR) {
            v.isLocked = true;
          }
        }
      } else { v.pos.x += dx * (speed / dist); v.pos.y += dy * (speed / dist); }
    }
    setStats(s => ({ ...s, active: currentVehicles.length }));
  }, [isRunning, speed, spawnRate, spawnVehicle]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);

    ctx.strokeStyle = 'rgba(30, 41, 59, 0.4)'; ctx.lineWidth = 1;
    for(let i=0; i<SIM_WIDTH; i+=100) { ctx.beginPath(); ctx.moveTo(i,0); ctx.lineTo(i,SIM_HEIGHT); ctx.stroke(); }
    for(let i=0; i<SIM_HEIGHT; i+=100) { ctx.beginPath(); ctx.moveTo(0,i); ctx.lineTo(SIM_WIDTH,i); ctx.stroke(); }

    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };

    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const isRepair = s.type === StationType.REPAIR;
      const w = s.width || (isRoll ? 150 : 130), h = s.height || (isRoll ? 64 : 44), x = s.pos.x - w / 2, y = s.pos.y - h / 2;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 12 && Math.abs(v.pos.y - s.pos.y) < 12);

      ctx.fillStyle = isRoll ? '#020617' : (isRepair ? '#1a0505' : '#0f172a');
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? '#10b981' : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(x, y, w, h, 10); ctx.fill(); ctx.stroke();

      ctx.fillStyle = isRepair ? '#fca5a5' : '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, y + 18);

      if (vehicleIn && vehicleIn.waitingTimer > 0) {
        const p = 1 - (vehicleIn.waitingTimer / s.wait);
        ctx.fillStyle = '#020617'; ctx.fillRect(x + 10, y + 35, w - 20, 6);
        ctx.fillStyle = isRepair ? '#ef4444' : '#10b981'; ctx.fillRect(x + 10, y + 35, (w - 20) * p, 6);
      }
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.shadowBlur = 10; ctx.shadowColor = v.color;
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();

      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px "Space Mono"'; ctx.textAlign = 'center';
      ctx.fillText(v.id, v.pos.x, v.pos.y - 18);

      if (v.hasPassedFAI) {
        ctx.fillStyle = '#10b981';
        ctx.beginPath(); ctx.arc(v.pos.x + 22, v.pos.y - 10, 4, 0, Math.PI * 2); ctx.fill();
      }
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));

      if (v.needsH2ORetesting) {
        v.targetPath = [...MAIN_PATH_POINTS].slice(16);
        v.pathIdx = 0;
        addLog(`RE-VALIDATE: [${v.id}] RETURNING TO H2O CHAMBER`);
      } else {
        v.targetPath = [...MAIN_PATH_POINTS].slice(15);
        v.pathIdx = 0;
        addLog(`REPAIRED: [${v.id}] RE-INTEGRATED TO MAIN LINE`);
      }
    }
  };

  const getRepairIcon = (type: string | null) => {
    switch(type) {
      case 'MECHANICAL': return <Wrench className="w-4 h-4" />;
      case 'LEAKAGE': return <WaterIcon className="w-4 h-4" />;
      case 'ELECTRICAL':
      case 'ELECTRONIC': return <ZapOff className="w-4 h-4" />;
      default: return <ShieldAlert className="w-4 h-4" />;
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      {/* SIDEBAR DASHBOARD */}
      <aside className="w-[400px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">

        {/* FIXED HEADER: OUTPUT KPI */}
        <div className="p-6 border-b border-slate-900/50 bg-slate-950/50 backdrop-blur-md">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-600 rounded-xl shadow-[0_0_15px_rgba(79,70,229,0.3)] ring-1 ring-white/10"><Boxes className="w-5 h-5 text-white" /></div>
              <div>
                <h1 className="text-[12px] font-black tracking-widest text-white uppercase">GOP Dashboard</h1>
                <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">IIoT Live Monitoring</p>
              </div>
            </div>
            <div className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border ${isRunning ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'} text-[8px] font-black uppercase tracking-widest`}>
               <Radio className={`w-3 h-3 ${isRunning ? 'animate-pulse' : ''}`} /> {isRunning ? 'Live' : 'Stopped'}
            </div>
          </div>

          <div className="p-4 bg-slate-900/50 rounded-2xl border border-white/5 relative overflow-hidden group">
            <div className="absolute top-0 left-0 w-full h-1 bg-slate-950">
                <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${(stats.produced/500)*100}%` }} />
            </div>
            <div className="flex justify-between items-end">
              <div>
                <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest block mb-1">Shift Progress</span>
                <div className="text-3xl font-black text-white tabular-nums tracking-tighter">
                    {stats.produced} <span className="text-slate-700 text-lg font-bold">/ 500</span>
                </div>
              </div>
              <div className="text-right">
                <TrendingUp className="w-4 h-4 text-indigo-400 ml-auto mb-1" />
                <span className="text-lg font-black text-indigo-400 tabular-nums tracking-tighter">{((stats.produced/500)*100).toFixed(1)}%</span>
              </div>
            </div>
          </div>
        </div>

        {/* QUICK NAV BAR */}
        <div className="flex bg-slate-950/40 p-1 mx-6 my-4 rounded-xl border border-slate-900/50 sticky top-0 z-40 backdrop-blur-sm">
          {[
            { id: 'stats', label: 'Stats', icon: <ActivitySquare className="w-3.5 h-3.5" /> },
            { id: 'repair', label: 'Repair', icon: <ShieldAlert className="w-3.5 h-3.5" /> },
            { id: 'shipping', label: 'Shipping', icon: <Truck className="w-3.5 h-3.5" /> }
          ].map(btn => (
            <button 
              key={btn.id} 
              onClick={() => scrollToSection(btn.id as any)}
              className="flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg text-slate-500 hover:text-white hover:bg-white/5 transition-all text-[9px] font-black uppercase tracking-widest"
            >
              {btn.icon} {btn.label}
            </button>
          ))}
        </div>

        {/* SCROLLABLE CONTENT AREA */}
        <div ref={dashboardRef} className="flex-1 overflow-y-auto custom-scrollbar px-6 pb-10 space-y-10 snap-y">

          <section ref={sectionRefs.stats} className="pt-2 snap-start">
            <div className="grid grid-cols-2 gap-3">
              <div className="p-4 bg-slate-900/40 border border-slate-800 rounded-2xl shadow-xl">
                <span className="text-[8px] font-black text-emerald-500 uppercase tracking-widest block mb-2">FTT Score</span>
                <div className="text-2xl font-black text-white tabular-nums">{((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%</div>
              </div>
              <div className="p-4 bg-slate-900/40 border border-slate-800 rounded-2xl shadow-xl">
                <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest block mb-2">FTR Rate</span>
                <div className="text-2xl font-black text-white tabular-nums">{((stats.ftrSuccesses / (stats.repairCompletedCount || 1)) * 100).toFixed(1)}%</div>
              </div>
            </div>

            <div className="mt-6 p-5 bg-slate-950/80 border border-slate-900 rounded-2xl shadow-2xl relative overflow-hidden">
                <h3 className="text-[9px] font-black text-slate-200 uppercase tracking-widest flex items-center gap-2 mb-4">
                    <ListFilter className="w-3.5 h-3.5 text-indigo-500" /> Defect Heatmap
                </h3>
                <div className="space-y-4">
                    {Object.entries(stats.categoryVolumes).map(([cat, val]) => (
                        <div key={cat} className="space-y-1.5">
                            <div className="flex justify-between text-[9px] font-black uppercase">
                                <span className="text-slate-500">{cat}</span>
                                <span className="text-slate-300">{val} U</span>
                            </div>
                            <div className="h-1 w-full bg-slate-900 rounded-full overflow-hidden">
                                <div className="h-full bg-indigo-600 transition-all duration-1000" style={{ width: `${(val / (stats.defects || 1)) * 100}%` }} />
                            </div>
                        </div>
                    ))}
                </div>
            </div>
          </section>

          <section ref={sectionRefs.repair} className="snap-start">
            <header className="flex items-center gap-3 mb-4">
                <div className="h-px flex-1 bg-slate-900"></div>
                <h2 className="text-[8px] font-black text-slate-700 uppercase tracking-[0.4em]">Section.02</h2>
                <div className="h-px flex-1 bg-slate-900"></div>
            </header>

            <div className="space-y-3">
              {vehiclesRef.current.filter(v=>v.inRepair).length === 0 ? (
                <div className="py-12 bg-slate-900/20 border border-dashed border-slate-800 rounded-2xl flex flex-col items-center justify-center opacity-30">
                    <CheckCircle2 className="w-8 h-8 text-emerald-500 mb-2" />
                    <span className="text-[8px] font-black uppercase tracking-widest text-slate-500">Nominal</span>
                </div>
              ) : (
                vehiclesRef.current.filter(v=>v.inRepair).map(v => (
                  <div key={v.id} className={`p-4 bg-slate-900/40 border ${v.isLocked ? 'border-rose-500/20' : 'border-slate-800'} rounded-2xl shadow-xl transition-all`}>
                    <div className="flex justify-between items-center mb-4">
                        <div className="flex items-center gap-3">
                            <div className="w-2.5 h-2.5 rounded-full animate-pulse" style={{ backgroundColor: v.color }}></div>
                            <span className="text-[12px] font-black text-white font-mono">{v.id}</span>
                        </div>
                        <div className="flex items-center gap-1.5 px-2 py-0.5 bg-slate-950/80 text-[7px] font-black uppercase text-rose-500 rounded-md border border-rose-500/10">
                            {getRepairIcon(v.failureType)} {v.failureType}
                        </div>
                    </div>

                    <button 
                        disabled={!v.isLocked}
                        onClick={() => validateRepair(v.id)} 
                        className={`w-full py-3 rounded-xl text-[9px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-2 shadow-xl ${
                            v.isLocked ? 'bg-indigo-600 text-white hover:bg-indigo-500 active:scale-95' : 'bg-slate-800 text-slate-600 opacity-50 cursor-not-allowed'
                        }`}
                    >
                       <ArrowRight className="w-4 h-4" /> {v.isLocked ? 'Verify' : 'Moving...'}
                    </button>
                  </div>
                ))
              )}
            </div>
          </section>

          <section ref={sectionRefs.shipping} className="snap-start pb-4">
            <header className="flex items-center gap-3 mb-4">
                <div className="h-px flex-1 bg-slate-900"></div>
                <h2 className="text-[8px] font-black text-slate-700 uppercase tracking-[0.4em]">Section.03</h2>
                <div className="h-px flex-1 bg-slate-900"></div>
            </header>

            <div className="bg-slate-900/40 border border-slate-800 rounded-2xl p-4 shadow-xl">
                <div className="space-y-2.5">
                    {vehiclesRef.current.filter(v=>v.readyForOffloading).map(v => (
                        <div key={v.id} className="p-3 bg-slate-950/60 border border-slate-900 rounded-xl flex items-center justify-between group">
                            <div className="flex items-center gap-3">
                                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
                                <span className="text-[10px] font-black text-slate-200 font-mono">{v.id}</span>
                            </div>
                            <span className="text-[7px] font-black text-emerald-500 uppercase">READY</span>
                        </div>
                    ))}
                    {vehiclesRef.current.filter(v=>v.readyForOffloading).length === 0 && (
                        <p className="text-center text-[9px] font-bold text-slate-700 py-4 italic uppercase tracking-widest">Awaiting cargo...</p>
                    )}
                </div>
            </div>
          </section>
        </div>

        {/* DASHBOARD FOOTER */}
        <div className="p-6 border-t border-slate-900 bg-slate-950/80 backdrop-blur-xl">
          <div className="grid grid-cols-2 gap-3 mb-3">
            <button onClick={() => setIsRunning(!isRunning)} className={`py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all flex justify-center gap-2 items-center shadow-xl ${isRunning ? 'bg-slate-900 text-slate-500 border border-white/5' : 'bg-indigo-600 text-white'}`}>
               {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'Hold' : 'Start'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; addLog("GLOBAL_PURGE: SYSTEM RESET"); }} className="py-3 bg-slate-900 text-slate-600 hover:text-rose-500 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all flex justify-center gap-2 items-center border border-white/5 shadow-xl">
              <RotateCcw className="w-4 h-4" /> Reset
            </button>
          </div>
          <button onClick={() => { vehiclesRef.current.forEach(v => { v.isLocked = false; }); }} className="w-full py-3 bg-indigo-500/5 border border-indigo-500/10 hover:border-indigo-500/30 text-indigo-400 text-[8px] font-black uppercase tracking-[0.3em] rounded-xl transition-all flex justify-center items-center gap-3 shadow-xl group">
             <Key className="w-4 h-4 group-hover:rotate-12 transition-transform" /> System Override
          </button>
        </div>
      </aside>

      {/* MAIN VIEWPORT - MAXIMIZED */}
      <main className="flex-1 relative flex flex-col bg-[#000000]">

        <header className="h-16 border-b border-slate-900/50 flex items-center justify-between px-8 bg-[#020617]/80 backdrop-blur-2xl z-20 shrink-0">
          <div className="flex gap-12">
            <div className="flex flex-col">
              <span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.3em] mb-1">Data Stream</span>
              <div className="flex items-center gap-2 text-[14px] font-black text-slate-200 tracking-tight">
                <Activity className="w-4 h-4 text-indigo-500" /> Plant_01 // Assy_A
              </div>
            </div>
            <div className="flex flex-col border-l border-slate-900 pl-12">
              <span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.3em] mb-1">Status</span>
              <div className="flex items-center gap-2 text-[14px] font-black text-emerald-400 tracking-tight">
                <MonitorDot className="w-4 h-4" /> Optimal_Performance
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="px-4 py-2 bg-indigo-500/5 rounded-xl border border-indigo-500/10 shadow-inner">
               <span className="text-[9px] font-black text-indigo-400 uppercase tracking-[0.2em] flex items-center gap-3">
                 <Radio className="w-3.5 h-3.5 animate-pulse" /> 100% VISUAL_SCALE
               </span>
             </div>
          </div>
        </header>

        {/* VIEWPORT 100% - Preenchimento total sem margens excessivas */}
        <div ref={viewportRef} className="flex-1 flex items-center justify-center relative bg-[#010103] overflow-hidden">
          <div 
            style={{ 
              width: SIM_WIDTH, 
              height: SIM_HEIGHT, 
              transform: `scale(${scale})`, 
              transformOrigin: 'center center',
              // Transição suave para mudanças de escala (ex: redimensionamento da janela)
              transition: 'transform 0.4s cubic-bezier(0.16, 1, 0.3, 1)'
            }} 
            className="relative bg-[#020617] rounded-[2rem] shrink-0 overflow-hidden border-2 border-slate-800 shadow-[0_50px_100px_-20px_rgba(0,0,0,0.8)] flex items-center justify-center"
          >
            {/* Background Grid sutil para sensação de profundidade */}
            <div className="absolute inset-0 opacity-[0.05] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#6366f1 1.5px, transparent 1.5px)', backgroundSize: '30px 30px' }} />

            <canvas ref={canvasRef} className="relative z-10" />

            {/* Texto de Fundo Dinâmico */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.02] pointer-events-none select-none text-center">
              <h2 className="text-[120px] font-black text-slate-500 uppercase tracking-[0.5em] leading-none">FACTORY</h2>
              <h2 className="text-[80px] font-black text-slate-600 uppercase tracking-[0.8em] leading-none">ALPHA_01</h2>
            </div>

            {/* Decoração de Canto Industrial */}
            <div className="absolute top-8 left-8 w-24 h-1 border-t-2 border-l-2 border-indigo-500/30 rounded-tl-lg" />
            <div className="absolute bottom-8 right-8 w-24 h-1 border-b-2 border-r-2 border-indigo-500/30 rounded-br-lg" />
          </div>
        </div>

        <footer className="h-16 bg-[#020617] border-t border-slate-900 flex items-center px-8 gap-8 shrink-0 overflow-hidden text-[8px] font-black uppercase tracking-[0.4em] text-slate-700 z-20">
          <div className="flex items-center gap-3 text-indigo-500 shrink-0 border-r border-slate-900 pr-8 h-full"><Terminal className="w-4 h-4" /> System_Bus</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-16 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (
                <span key={i} className={`flex gap-3 items-center ${l.includes('FAIL') ? 'text-rose-500' : 'text-slate-500'}`}>
                  <div className={`w-1 h-1 rounded-full ${l.includes('FAIL') ? 'bg-rose-500 animate-pulse' : 'bg-slate-800'}`} /> {l}
                </span>
              ))}
              {logs.length === 0 && <span className="opacity-40 italic tracking-widest">Streaming live telemetry... Systems normal...</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 90s linear infinite; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #334155; }
      `}</style>
    </div>
  );
};

export default App;

export interface Point {
  x: number;
  y: number;
}

export enum StationType {
  STORAGE = 'STORAGE',
  ASSEMBLY = 'ASSEMBLY',
  MGR = 'MGR',
  TEST = 'TEST',
  QUALITY = 'QUALITY',
  REPAIR = 'REPAIR',
  SHIPPING = 'SHIPPING',
  PRE_DELIVERY = 'PRE_DELIVERY'
}

export type FailurePriority = 'P1' | 'P2' | 'P3' | 'P4';
export type FailureType = 'ELECTRICAL' | 'ELECTRONIC' | 'MECHANICAL' | 'LEAKAGE';
export type QualityStatus = 'NONE' | 'PASS' | 'FAIL';
export type RollTestStep = 'READY' | 'ECATS' | 'ACCEL' | 'BRAKE' | 'DONE';
export type AndonStatus = 'GREEN' | 'YELLOW' | 'RED';

export interface Station {
  id: string;
  name: string;
  pos: Point;
  wait: number; 
  type: StationType;
  width?: number;
  height?: number;
  isBroken?: boolean;
}

export interface Vehicle {
  id: string;
  pos: Point;
  rotation: number;
  pathIdx: number;
  targetPath: Point[];
  waitingTimer: number;
  hasDefect: boolean;
  color: string;
  baseColor: string;
  isLocked: boolean;
  failureType: FailureType | null;
  priority: FailurePriority | null;
  entryBufferTime: number | null; // Timestamp de entrada no buffer
  currentLeadTime: number;

  viaVerde: boolean; 
  rollTestStatus: QualityStatus;
  waterTestStatus: QualityStatus;
  preDeliveryStatus: QualityStatus;

  needsH2ORetesting: boolean;
  readyForOffloading: boolean;
  inRepair: boolean;
  assignedCabinId: string | null;
  rollStep: RollTestStep;
  hasPassedFAI: boolean;
}

export interface SimulationStats {
  produced: number;
  defects: number;
  active: number;
  totalStarted: number;
  passedFirstTime: number; 
  ftrSuccesses: number;    
  repairCompletedCount: number;
  categoryVolumes: Record<FailureType, number>;
  rollTestProcessed: number;
  andon: AndonStatus;
  currentTakt: number;
  targetTakt: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Boxes, ArrowRight, Truck, MonitorDot, Wrench, ZapOff, Droplets as WaterIcon,
  ShieldCheck, TrendingUp, History, ListFilter, Command, Timer, AlertTriangle
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, QualityStatus, StationType, FailurePriority, AndonStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(440); 
  const [speed, setSpeed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [commandInput, setCommandInput] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, andon: 'GREEN', currentTakt: 57.6, targetTakt: 57.6
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const dashboardRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const sectionRefs = {
    stats: useRef<HTMLElement>(null),
    repair: useRef<HTMLElement>(null),
    shipping: useRef<HTMLElement>(null)
  };

  const scrollToSection = (section: keyof typeof sectionRefs) => {
    sectionRefs[section].current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 20) / SIM_WIDTH, (rect.height - 20) / SIM_HEIGHT);
    setScale(s);
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    const timer = setTimeout(updateScale, 150);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => {
      window.removeEventListener('resize', updateScale);
      clearTimeout(timer);
    };
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const handleCommand = (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = commandInput.trim().toLowerCase();
    setCommandInput('');

    if (cmd === '/status') {
      addLog(`STATUS: Prod=${stats.produced} | FTT=${((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%`);
    } else if (cmd.startsWith('/takt ')) {
      const val = parseFloat(cmd.split(' ')[1]);
      if (!isNaN(val)) {
        setStats(s => ({ ...s, targetTakt: val }));
        addLog(`CONFIG: Target Takt ajustado para ${val}s`);
      }
    } else if (cmd.startsWith('/priorizar ')) {
      const vin = cmd.split(' ')[1].toUpperCase();
      const v = vehiclesRef.current.find(veh => veh.id === vin);
      if (v && v.inRepair) {
        v.priority = 'P1';
        addLog(`PRIORITY: VIN ${vin} elevado para P1 (Override)`);
      }
    } else if (cmd.startsWith('/quebra ')) {
      const station = cmd.split(' ')[1];
      addLog(`ALERTA: Simulação de quebra em ${station.toUpperCase()} iniciada.`);
      setStats(s => ({ ...s, andon: 'RED' }));
    } else {
      addLog(`ERRO: Comando "${cmd}" não reconhecido.`);
    }
  };

  const spawnVehicle = useCallback(() => {
    const id = "VIN" + Math.random().toString(36).substr(2, 5).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.25, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, priority: null, entryBufferTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY',
      hasPassedFAI: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const moveToRepair = (v: Vehicle, type: FailureType, source: string) => {
    v.viaVerde = false; v.inRepair = true; v.failureType = type;
    v.entryBufferTime = Date.now();
    v.color = '#ef4444';

    // Lógica de Prioridade Digital Twin
    if (type === 'LEAKAGE') v.priority = 'P1';
    else if (source.includes('ROLL')) v.priority = 'P2';
    else v.priority = 'P3';

    const entry = REPAIR_PATH_POINTS[0], junction = REPAIR_PATH_POINTS[1], mecCell = REPAIR_PATH_POINTS[2],
          leakCell = REPAIR_PATH_POINTS[3], elecCell = REPAIR_PATH_POINTS[4], 
          returnPath = REPAIR_PATH_POINTS[5], exitPath = REPAIR_PATH_POINTS[6];

    v.targetPath = type === 'MECHANICAL' ? [entry, junction, mecCell, returnPath, exitPath] :
                  type === 'LEAKAGE' ? [entry, junction, leakCell, returnPath, exitPath] :
                  [entry, junction, elecCell, returnPath, exitPath];

    v.pathIdx = 0;
    setStats(s => ({ 
      ...s, 
      defects: s.defects + 1, 
      categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } 
    }));
    addLog(`FAIL: [${v.id}] @ ${source} -> Prioridade ${v.priority}`);
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;

    // Andon Logic
    const bufferCount = currentVehicles.filter(v => v.inRepair).length;
    let andon: AndonStatus = 'GREEN';
    if (bufferCount > 8) andon = 'RED';
    else if (bufferCount > 4) andon = 'YELLOW';

    if (stats.andon !== andon) setStats(s => ({ ...s, andon }));

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);

      const currentSpeed = speed * (stats.andon === 'RED' ? 0.5 : stats.andon === 'YELLOW' ? 0.8 : 1);

      if (dist < currentSpeed) {
        v.pos = { ...target }; v.pathIdx++;

        // Roll Test Logic: Only enter if cabin is empty (Digital Twin Rule)
        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE' && !v.hasPassedFAI) {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null;
        }

        const currentStation = (!v.inRepair ? STATIONS[v.pathIdx] : null) || 
                               Object.values(REPAIR_STATIONS).find(s => v.inRepair && Math.abs(s.pos.x - v.pos.x) < 8 && Math.abs(s.pos.y - v.pos.y) < 8) ||
                               PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (currentStation) {
          v.waitingTimer = currentStation.wait;
          if (currentStation.name === 'FAI QC') v.hasPassedFAI = true;
          if (currentStation.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.4) moveToRepair(v, Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLL TEST');
            else v.rollTestStatus = 'PASS';
          }
          if (currentStation.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.2) { v.needsH2ORetesting = true; moveToRepair(v, 'LEAKAGE', 'H2O TEST'); }
            else v.waterTestStatus = 'PASS';
          }
          if (currentStation.name === 'EMBARQUE') v.readyForOffloading = true;
          if (v.inRepair && currentStation.type === StationType.REPAIR) v.isLocked = true;
        }
      } else { v.pos.x += dx * (currentSpeed / dist); v.pos.y += dy * (currentSpeed / dist); }
    }
  }, [isRunning, speed, spawnRate, spawnVehicle, stats.andon]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const isRepair = s.type === StationType.REPAIR;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 12 && Math.abs(v.pos.y - s.pos.y) < 12);
      ctx.fillStyle = isRoll ? '#020617' : (isRepair ? '#1a0505' : '#0f172a');
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? (isRepair ? '#ef4444' : '#10b981') : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(s.pos.x - (s.width || 130)/2, s.pos.y - (s.height || 44)/2, s.width || 130, s.height || 44, 10); ctx.fill(); ctx.stroke();
      ctx.fillStyle = isRepair ? '#fca5a5' : '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, s.pos.y - 4);
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();
      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px font-mono'; ctx.fillText(v.id, v.pos.x, v.pos.y - 18);
      if (v.priority === 'P1') { ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(v.pos.x + 22, v.pos.y - 10, 5, 0, Math.PI * 2); ctx.fill(); }
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      v.targetPath = v.needsH2ORetesting ? [...MAIN_PATH_POINTS].slice(16) : [...MAIN_PATH_POINTS].slice(15);
      v.pathIdx = 0;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));
      addLog(`REPAIRED: [${v.id}] Retornando para validação.`);
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      <aside className="w-[400px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">
        <div className="p-6 border-b border-slate-900/50 space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-600 rounded-xl"><Boxes className="w-5 h-5 text-white" /></div>
              <div><h1 className="text-[12px] font-black text-white uppercase">Digital Twin v1.0</h1><p className="text-[9px] text-slate-500 uppercase">Automotive Assembly</p></div>
            </div>
            <div className={`px-3 py-1.5 rounded-lg border flex items-center gap-2 text-[9px] font-black uppercase ${stats.andon === 'GREEN' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : stats.andon === 'YELLOW' ? 'bg-amber-500/10 border-amber-500/20 text-amber-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'}`}>
              <div className={`w-2 h-2 rounded-full ${stats.andon === 'GREEN' ? 'bg-emerald-500' : stats.andon === 'YELLOW' ? 'bg-amber-500' : 'bg-rose-500 animate-pulse'}`} /> Andon {stats.andon}
            </div>
          </div>

          <div className="p-4 bg-slate-900/50 rounded-2xl border border-white/5 space-y-4">
            <div className="flex justify-between items-end">
              <div><span className="text-[9px] font-black text-slate-600 uppercase">Shift Target</span><div className="text-3xl font-black text-white">{stats.produced} <span className="text-slate-700 text-lg">/ 500</span></div></div>
              <div className="text-right"><TrendingUp className="w-4 h-4 text-indigo-400 ml-auto" /><span className="text-lg font-black text-indigo-400">{((stats.produced/500)*100).toFixed(1)}%</span></div>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
              <div className="p-3 bg-slate-950 rounded-xl border border-white/5"><span className="text-[8px] font-bold text-slate-600 block mb-1 uppercase">Takt Real</span><div className="text-sm font-black text-white flex items-center gap-2"><Timer className="w-3 h-3 text-indigo-400" /> {stats.currentTakt}s</div></div>
              <div className="p-3 bg-slate-950 rounded-xl border border-white/5"><span className="text-[8px] font-bold text-slate-600 block mb-1 uppercase">Target</span><div className="text-sm font-black text-slate-400">{stats.targetTakt}s</div></div>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-6 space-y-8">
          <section className="pt-6">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><ShieldAlert className="w-4 h-4" /> Buffer Management</h3>
            <div className="space-y-3">
              {vehiclesRef.current.filter(v => v.inRepair).sort((a,b) => (a.priority === 'P1' ? -1 : 1)).map(v => (
                <div key={v.id} className={`p-4 bg-slate-900/40 border rounded-2xl transition-all ${v.priority === 'P1' ? 'border-rose-500/30 bg-rose-500/5' : 'border-slate-800'}`}>
                  <div className="flex justify-between items-center mb-3">
                    <span className="text-[12px] font-black text-white font-mono">{v.id}</span>
                    <span className={`px-2 py-0.5 rounded text-[8px] font-black ${v.priority === 'P1' ? 'bg-rose-500 text-white' : 'bg-slate-800 text-slate-400'}`}>{v.priority}</span>
                  </div>
                  <div className="flex justify-between items-center gap-2">
                    <div className="text-[9px] font-bold text-slate-500 uppercase flex items-center gap-1"><History className="w-3 h-3" /> Aging: {Math.floor(v.currentLeadTime/60)}m</div>
                    <button disabled={!v.isLocked} onClick={() => validateRepair(v.id)} className={`px-4 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-wider ${v.isLocked ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-800 text-slate-600'}`}>Verify</button>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        <div className="p-6 border-t border-slate-900 bg-slate-950/80">
          <form onSubmit={handleCommand} className="relative group mb-4">
             <Command className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600 group-focus-within:text-indigo-500 transition-colors" />
             <input value={commandInput} onChange={e => setCommandInput(e.target.value)} placeholder="Console / Command..." className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-10 pr-4 text-[10px] font-mono text-indigo-400 focus:outline-none focus:border-indigo-500 transition-all" />
          </form>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => setIsRunning(!isRunning)} className="py-3 bg-slate-900 rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-2">{isRunning ? <Pause className="w-3.5 h-3.5" /> : <Play className="w-3.5 h-3.5" />} {isRunning ? 'Hold' : 'Start'}</button>
            <button onClick={() => vehiclesRef.current = []} className="py-3 bg-slate-900 rounded-xl text-[9px] font-black uppercase flex items-center justify-center gap-2 text-rose-500"><RotateCcw className="w-3.5 h-3.5" /> Reset</button>
          </div>
        </div>
      </aside>

      <main className="flex-1 relative flex flex-col bg-[#000]">
        <header className="h-16 border-b border-slate-900/50 flex items-center justify-between px-8 bg-[#020617]/80 backdrop-blur-xl z-20 shrink-0">
          <div className="flex gap-12">
            <div className="flex flex-col"><span className="text-[8px] font-black text-slate-700 uppercase mb-1">Telemetry Stream</span><div className="flex items-center gap-2 text-sm font-black text-slate-200"><Activity className="w-4 h-4 text-indigo-500" /> DigitalTwin_Node_01</div></div>
            <div className="flex flex-col border-l border-slate-900 pl-12"><span className="text-[8px] font-black text-slate-700 uppercase mb-1">Status</span><div className={`flex items-center gap-2 text-sm font-black ${stats.andon === 'RED' ? 'text-rose-500' : 'text-emerald-400'}`}><MonitorDot className="w-4 h-4" /> Operational_Sync</div></div>
          </div>
          <div className="flex items-center gap-4">
             {stats.andon !== 'GREEN' && <div className="flex items-center gap-2 px-3 py-1.5 bg-rose-500/10 border border-rose-500/20 text-rose-500 text-[9px] font-black rounded-lg animate-pulse"><AlertTriangle className="w-3.5 h-3.5" /> GARGALO IDENTIFICADO</div>}
          </div>
        </header>

        <div ref={viewportRef} className="flex-1 flex items-center justify-center relative bg-[#010103] overflow-hidden">
          <div style={{ width: SIM_WIDTH, height: SIM_HEIGHT, transform: `scale(${scale})`, transformOrigin: 'center center', transition: 'transform 0.4s cubic-bezier(0.16, 1, 0.3, 1)' }} className="relative bg-[#020617] rounded-[2rem] border-2 border-slate-800 shadow-2xl flex items-center justify-center">
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#6366f1 1.5px, transparent 1.5px)', backgroundSize: '30px 30px' }} />
            <canvas ref={canvasRef} className="relative z-10" />
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 opacity-[0.02] pointer-events-none text-center">
              <h2 className="text-[120px] font-black text-slate-500 uppercase tracking-[0.5em]">FACTORY</h2>
            </div>
          </div>
        </div>

        <footer className="h-14 bg-[#020617] border-t border-slate-900 flex items-center px-8 gap-8 shrink-0 overflow-hidden text-[8px] font-black uppercase text-slate-700 z-20">
          <div className="flex items-center gap-3 text-indigo-500 border-r border-slate-900 pr-8 h-full"><Terminal className="w-4 h-4" /> BUS_STREAM</div>
          <div className="flex-1 overflow-hidden relative h-full flex items-center">
            <div className="flex gap-16 animate-marquee items-center whitespace-nowrap">
              {logs.map((l, i) => (<span key={i} className={`flex gap-3 items-center ${l.includes('FAIL') || l.includes('ERRO') ? 'text-rose-500' : 'text-slate-500'}`}><div className={`w-1 h-1 rounded-full ${l.includes('FAIL') ? 'bg-rose-500 animate-pulse' : 'bg-slate-800'}`} /> {l}</span>))}
              {logs.length === 0 && <span className="opacity-40 tracking-widest italic">Iniciando streaming de telemetria IIoT...</span>}
            </div>
          </div>
        </footer>
      </main>

      <style>{`
        @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
        .animate-marquee { animation: marquee 90s linear infinite; }
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, Pause, RotateCcw, CheckCircle2, ShieldAlert, Terminal, Key,
  BarChart, LayoutGrid, AlertCircle, Gauge, Zap, ActivitySquare, Radio, Activity,
  Boxes, ArrowRight, Truck, MonitorDot, Wrench, ZapOff, Droplets as WaterIcon,
  ShieldCheck, TrendingUp, History, ListFilter, Command, Timer, AlertTriangle,
  ChevronLeft, ChevronRight, Cpu
} from 'lucide-react';
import { 
  SIM_WIDTH, SIM_HEIGHT, COLORS, MAIN_PATH_POINTS, REPAIR_PATH_POINTS, STATIONS, 
  REPAIR_STATIONS, ROLL_TEST_BRANCHES, FORK_POINT_IDX, MERGE_POINT_IDX, PARALLEL_ROLL_STATIONS
} from './constants';
import { Vehicle, Point, SimulationStats, FailureType, QualityStatus, StationType, FailurePriority, AndonStatus } from './types';

const VEHICLE_IMAGE_SRC = "data:image/svg+xml;base64,";

const App: React.FC = () => {
  const [isRunning, setIsRunning] = useState(true);
  const [spawnRate, setSpawnRate] = useState(440); 
  const [speed, setSpeed] = useState(3.4);
  const [scale, setScale] = useState(1);
  const [commandInput, setCommandInput] = useState('');
  const [stats, setStats] = useState<SimulationStats>({ 
    produced: 0, defects: 0, active: 0, totalStarted: 0, passedFirstTime: 0, 
    ftrSuccesses: 0, repairCompletedCount: 0,
    categoryVolumes: { ELECTRICAL: 0, ELECTRONIC: 0, MECHANICAL: 0, LEAKAGE: 0 },
    rollTestProcessed: 0, andon: 'GREEN', currentTakt: 57.6, targetTakt: 57.6
  });
  const [logs, setLogs] = useState<string[]>([]);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const analyticsScrollRef = useRef<HTMLDivElement>(null);
  const vehiclesRef = useRef<Vehicle[]>([]);
  const frameCountRef = useRef(0);
  const vehicleImage = useRef<HTMLImageElement | null>(null);

  const sectionRefs = {
    stats: useRef<HTMLElement>(null),
    repair: useRef<HTMLElement>(null),
    shipping: useRef<HTMLElement>(null)
  };

  const scrollToSection = (section: keyof typeof sectionRefs) => {
    sectionRefs[section].current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  const scrollAnalytics = (direction: 'left' | 'right') => {
    if (analyticsScrollRef.current) {
      const offset = direction === 'left' ? -300 : 300;
      analyticsScrollRef.current.scrollBy({ left: offset, behavior: 'smooth' });
    }
  };

  const updateScale = useCallback(() => {
    if (!viewportRef.current || !canvasRef.current) return;
    const rect = viewportRef.current.getBoundingClientRect();
    const s = Math.min((rect.width - 10) / SIM_WIDTH, (rect.height - 10) / SIM_HEIGHT);
    setScale(s);
    const dpr = window.devicePixelRatio || 1;
    canvasRef.current.width = SIM_WIDTH * dpr;
    canvasRef.current.height = SIM_HEIGHT * dpr;
    const ctx = canvasRef.current.getContext('2d');
    if (ctx) { ctx.resetTransform(); ctx.scale(dpr, dpr); }
  }, []);

  useEffect(() => {
    window.addEventListener('resize', updateScale);
    const timer = setTimeout(updateScale, 150);
    const img = new Image();
    img.src = VEHICLE_IMAGE_SRC;
    img.onload = () => { vehicleImage.current = img; };
    return () => {
      window.removeEventListener('resize', updateScale);
      clearTimeout(timer);
    };
  }, [updateScale]);

  const addLog = (msg: string) => setLogs(p => [msg, ...p].slice(0, 15));

  const handleCommand = (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = commandInput.trim().toLowerCase();
    setCommandInput('');

    if (cmd === '/status') {
      addLog(`STATUS: Prod=${stats.produced} | FTT=${((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%`);
    } else if (cmd.startsWith('/takt ')) {
      const val = parseFloat(cmd.split(' ')[1]);
      if (!isNaN(val)) {
        setStats(s => ({ ...s, targetTakt: val }));
        addLog(`CONFIG: Target Takt ajustado para ${val}s`);
      }
    } else if (cmd.startsWith('/priorizar ')) {
      const vin = cmd.split(' ')[1].toUpperCase();
      const v = vehiclesRef.current.find(veh => veh.id === vin);
      if (v && v.inRepair) {
        v.priority = 'P1';
        addLog(`PRIORITY: VIN ${vin} elevado para P1 (Override)`);
      }
    } else if (cmd.startsWith('/quebra ')) {
      const station = cmd.split(' ')[1];
      addLog(`ALERTA: Simulação de quebra em ${station.toUpperCase()} iniciada.`);
      setStats(s => ({ ...s, andon: 'RED' }));
    } else {
      addLog(`ERRO: Comando "${cmd}" não reconhecido.`);
    }
  };

  const spawnVehicle = useCallback(() => {
    const id = "VIN" + Math.random().toString(36).substr(2, 5).toUpperCase();
    const bodyColors = ['#f8fafc', '#ef4444', '#3b82f6', '#10b981', '#f59e0b'];
    const bodyColor = bodyColors[Math.floor(Math.random() * bodyColors.length)];
    const newVehicle: Vehicle = {
      id, pos: { ...MAIN_PATH_POINTS[0] }, rotation: 0, pathIdx: 0, targetPath: [...MAIN_PATH_POINTS],
      waitingTimer: 0, hasDefect: Math.random() < 0.25, isLocked: false,
      color: bodyColor, baseColor: bodyColor,
      failureType: null, priority: null, entryBufferTime: null, currentLeadTime: 0,
      viaVerde: true, rollTestStatus: 'NONE', waterTestStatus: 'NONE', preDeliveryStatus: 'NONE',
      needsH2ORetesting: false, readyForOffloading: false, inRepair: false, assignedCabinId: null, rollStep: 'READY',
      hasPassedFAI: false
    };
    vehiclesRef.current.push(newVehicle);
    setStats(s => ({ ...s, totalStarted: s.totalStarted + 1 }));
  }, []);

  const moveToRepair = (v: Vehicle, type: FailureType, source: string) => {
    v.viaVerde = false; v.inRepair = true; v.failureType = type;
    v.entryBufferTime = Date.now();
    v.color = '#ef4444';

    if (type === 'LEAKAGE') v.priority = 'P1';
    else if (source.includes('ROLL')) v.priority = 'P2';
    else v.priority = 'P3';

    const entry = REPAIR_PATH_POINTS[0], junction = REPAIR_PATH_POINTS[1], mecCell = REPAIR_PATH_POINTS[2],
          leakCell = REPAIR_PATH_POINTS[3], elecCell = REPAIR_PATH_POINTS[4], 
          returnPath = REPAIR_PATH_POINTS[5], exitPath = REPAIR_PATH_POINTS[6];

    v.targetPath = type === 'MECHANICAL' ? [entry, junction, mecCell, returnPath, exitPath] :
                  type === 'LEAKAGE' ? [entry, junction, leakCell, returnPath, exitPath] :
                  [entry, junction, elecCell, returnPath, exitPath];

    v.pathIdx = 0;
    setStats(s => ({ 
      ...s, 
      defects: s.defects + 1, 
      categoryVolumes: { ...s.categoryVolumes, [type]: s.categoryVolumes[type] + 1 } 
    }));
    addLog(`FAIL: [${v.id}] @ ${source} -> Prioridade ${v.priority}`);
  };

  const updateSimulation = useCallback(() => {
    if (!isRunning) return;
    frameCountRef.current++;
    if (frameCountRef.current % spawnRate === 0) spawnVehicle();

    const currentVehicles = vehiclesRef.current;

    const bufferCount = currentVehicles.filter(v => v.inRepair).length;
    let andon: AndonStatus = 'GREEN';
    if (bufferCount > 8) andon = 'RED';
    else if (bufferCount > 4) andon = 'YELLOW';

    if (stats.andon !== andon) setStats(s => ({ ...s, andon }));

    for (let i = currentVehicles.length - 1; i >= 0; i--) {
      const v = currentVehicles[i];
      if (v.isLocked) continue; 
      if (v.inRepair) v.currentLeadTime++;

      if (v.waitingTimer > 0) {
        v.waitingTimer--;
        continue; 
      }

      const target = v.targetPath[v.pathIdx + 1];
      if (!target) {
        if (v.viaVerde) setStats(s => ({ ...s, passedFirstTime: s.passedFirstTime + 1 }));
        setStats(s => ({ ...s, produced: s.produced + 1 }));
        currentVehicles.splice(i, 1);
        continue;
      }

      const hasBlocker = currentVehicles.some(o => o.id !== v.id && Math.sqrt(Math.pow(o.pos.x - v.pos.x, 2) + Math.pow(o.pos.y - v.pos.y, 2)) < 65 && o.pathIdx >= v.pathIdx);
      if (hasBlocker) continue;

      const dx = target.x - v.pos.x, dy = target.y - v.pos.y, dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > 0.1) v.rotation = Math.atan2(dy, dx);

      const currentSpeed = speed * (stats.andon === 'RED' ? 0.5 : stats.andon === 'YELLOW' ? 0.8 : 1);

      if (dist < currentSpeed) {
        v.pos = { ...target }; v.pathIdx++;

        if (v.pathIdx === FORK_POINT_IDX && !v.inRepair && v.rollTestStatus === 'NONE' && !v.hasPassedFAI) {
          const availableIdx = [0, 1, 2].find(idx => !currentVehicles.some(other => other.assignedCabinId === PARALLEL_ROLL_STATIONS[idx].id));
          if (availableIdx !== undefined) {
            v.assignedCabinId = PARALLEL_ROLL_STATIONS[availableIdx].id;
            v.targetPath = [...ROLL_TEST_BRANCHES[availableIdx], ...MAIN_PATH_POINTS.slice(MERGE_POINT_IDX + 1)];
            v.pathIdx = 0;
          } else { v.pathIdx--; continue; } 
        }

        if (v.assignedCabinId && Math.abs(v.pos.x - MAIN_PATH_POINTS[MERGE_POINT_IDX].x) < 5 && Math.abs(v.pos.y - MAIN_PATH_POINTS[MERGE_POINT_IDX].y) < 5) {
          v.assignedCabinId = null;
        }

        const currentStation = (!v.inRepair ? STATIONS[v.pathIdx] : null) || 
                               Object.values(REPAIR_STATIONS).find(s => v.inRepair && Math.abs(s.pos.x - v.pos.x) < 8 && Math.abs(s.pos.y - v.pos.y) < 8) ||
                               PARALLEL_ROLL_STATIONS.find(ps => Math.abs(ps.pos.x - v.pos.x) < 5 && Math.abs(ps.pos.y - v.pos.y) < 5);

        if (currentStation) {
          v.waitingTimer = currentStation.wait;
          if (currentStation.name === 'FAI QC') v.hasPassedFAI = true;
          if (currentStation.name.startsWith('Teste Rolo')) {
            if (v.hasDefect && Math.random() < 0.4) moveToRepair(v, Math.random() > 0.5 ? 'ELECTRONIC' : 'MECHANICAL', 'ROLL TEST');
            else v.rollTestStatus = 'PASS';
          }
          if (currentStation.name === 'SISTEMA ÁGUA') {
            if (v.hasDefect && Math.random() < 0.2) { v.needsH2ORetesting = true; moveToRepair(v, 'LEAKAGE', 'H2O TEST'); }
            else v.waterTestStatus = 'PASS';
          }
          if (currentStation.name === 'EMBARQUE') v.readyForOffloading = true;
          if (v.inRepair && currentStation.type === StationType.REPAIR) v.isLocked = true;
        }
      } else { v.pos.x += dx * (currentSpeed / dist); v.pos.y += dy * (currentSpeed / dist); }
    }
  }, [isRunning, speed, spawnRate, spawnVehicle, stats.andon]);

  const draw = useCallback((ctx: CanvasRenderingContext2D) => {
    ctx.clearRect(0, 0, SIM_WIDTH, SIM_HEIGHT);
    const pathLine = (pts: Point[], col = '#1e293b', w = 32) => {
      ctx.beginPath(); ctx.strokeStyle = col; ctx.lineWidth = w; ctx.lineCap = 'round'; ctx.lineJoin = 'round';
      ctx.moveTo(pts[0].x, pts[0].y); pts.forEach(p => ctx.lineTo(p.x, p.y)); ctx.stroke();
    };
    pathLine(MAIN_PATH_POINTS.slice(0, FORK_POINT_IDX + 1));
    ROLL_TEST_BRANCHES.forEach(b => pathLine(b, '#0f172a', 38));
    pathLine(MAIN_PATH_POINTS.slice(MERGE_POINT_IDX));
    pathLine(REPAIR_PATH_POINTS, '#1a0505', 36);

    [...Object.values(STATIONS), ...Object.values(REPAIR_STATIONS), ...PARALLEL_ROLL_STATIONS].forEach(s => {
      const isRoll = s.name.startsWith('Teste Rolo');
      const isRepair = s.type === StationType.REPAIR;
      const vehicleIn = vehiclesRef.current.find(v => Math.abs(v.pos.x - s.pos.x) < 12 && Math.abs(v.pos.y - s.pos.y) < 12);
      ctx.fillStyle = isRoll ? '#020617' : (isRepair ? '#1a0505' : '#0f172a');
      ctx.strokeStyle = vehicleIn && vehicleIn.waitingTimer > 0 ? (isRepair ? '#ef4444' : '#10b981') : '#334155';
      ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(s.pos.x - (s.width || 130)/2, s.pos.y - (s.height || 44)/2, s.width || 130, s.height || 44, 10); ctx.fill(); ctx.stroke();
      ctx.fillStyle = isRepair ? '#fca5a5' : '#94a3b8'; ctx.font = 'bold 9px Inter'; ctx.textAlign = 'center';
      ctx.fillText(s.name.toUpperCase(), s.pos.x, s.pos.y - 4);
    });

    vehiclesRef.current.forEach(v => {
      if (!vehicleImage.current) return;
      ctx.save(); ctx.translate(v.pos.x, v.pos.y); ctx.rotate(v.rotation);
      ctx.drawImage(vehicleImage.current, -18, -9, 36, 18);
      ctx.globalCompositeOperation = 'multiply'; ctx.fillStyle = v.color; ctx.beginPath(); ctx.roundRect(-18, -9, 36, 18, 4); ctx.fill();
      ctx.restore();
      ctx.fillStyle = '#fff'; ctx.font = 'bold 8px font-mono'; ctx.fillText(v.id, v.pos.x, v.pos.y - 18);
      if (v.priority === 'P1') { ctx.fillStyle = '#ef4444'; ctx.beginPath(); ctx.arc(v.pos.x + 22, v.pos.y - 10, 5, 0, Math.PI * 2); ctx.fill(); }
    });
  }, []);

  useEffect(() => {
    let fId: number; const loop = () => { updateSimulation(); if (canvasRef.current) draw(canvasRef.current.getContext('2d')!); fId = requestAnimationFrame(loop); };
    fId = requestAnimationFrame(loop); return () => cancelAnimationFrame(fId);
  }, [updateSimulation, draw]);

  const validateRepair = (id: string) => {
    const v = vehiclesRef.current.find(veh => veh.id === id);
    if (v) { 
      v.isLocked = false; v.waitingTimer = 0; v.inRepair = false; v.color = v.baseColor;
      v.targetPath = v.needsH2ORetesting ? [...MAIN_PATH_POINTS].slice(16) : [...MAIN_PATH_POINTS].slice(15);
      v.pathIdx = 0;
      setStats(s => ({ ...s, ftrSuccesses: s.ftrSuccesses + 1, repairCompletedCount: s.repairCompletedCount + 1 }));
      addLog(`REPAIRED: [${v.id}] Retornando para validação.`);
    }
  };

  return (
    <div className="flex h-screen w-screen bg-[#020617] text-slate-400 font-sans antialiased overflow-hidden">

      {/* DIGITAL TWIN SIDEBAR DASHBOARD */}
      <aside className="w-[420px] bg-[#020617] border-r border-slate-900 flex flex-col shrink-0 z-30 shadow-2xl relative">

        {/* FIXED PRODUCTION HEADER */}
        <div className="p-6 border-b border-slate-900/50 bg-slate-950/70 backdrop-blur-xl z-50">
          <div className="flex items-center justify-between mb-6">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-indigo-600 rounded-xl shadow-[0_0_15px_rgba(79,70,229,0.3)]"><Boxes className="w-5 h-5 text-white" /></div>
              <div>
                <h1 className="text-[14px] font-black text-white uppercase tracking-tighter flex items-center gap-2">Digital Twin <span className="text-[10px] bg-white/10 px-1.5 py-0.5 rounded">v1.2</span></h1>
                <p className="text-[9px] text-slate-500 uppercase font-bold tracking-[0.2em]">Plant.Control.Alpha</p>
              </div>
            </div>
            <div className={`px-4 py-2 rounded-xl border flex items-center gap-2 text-[10px] font-black uppercase transition-colors ${stats.andon === 'GREEN' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : stats.andon === 'YELLOW' ? 'bg-amber-500/10 border-amber-500/20 text-amber-500' : 'bg-rose-500/10 border-rose-500/20 text-rose-500'}`}>
              <div className={`w-2.5 h-2.5 rounded-full ${stats.andon === 'GREEN' ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : stats.andon === 'YELLOW' ? 'bg-amber-500 shadow-[0_0_8px_#f59e0b]' : 'bg-rose-500 animate-pulse shadow-[0_0_12px_#ef4444]'}`} /> 
              {stats.andon}
            </div>
          </div>

          <div className="p-5 bg-slate-900/40 rounded-3xl border border-white/5 relative overflow-hidden group shadow-inner">
            <div className="absolute top-0 left-0 w-full h-1 bg-slate-950">
                <div className="h-full bg-indigo-500 transition-all duration-1000 shadow-[0_0_10px_#6366f1]" style={{ width: `${(stats.produced/500)*100}%` }} />
            </div>
            <div className="flex justify-between items-end">
              <div>
                <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest block mb-1">Production Quota</span>
                <div className="text-4xl font-black text-white tabular-nums tracking-tighter">
                    {stats.produced} <span className="text-slate-700 text-xl font-bold">/ 500</span>
                </div>
              </div>
              <div className="text-right">
                <TrendingUp className="w-5 h-5 text-indigo-400 ml-auto mb-1" />
                <span className="text-xl font-black text-indigo-400 tabular-nums tracking-tighter">{((stats.produced/500)*100).toFixed(1)}%</span>
              </div>
            </div>
          </div>
        </div>

        {/* NAVIGATION TABS */}
        <div className="flex bg-slate-950/40 p-1.5 mx-6 mt-6 rounded-2xl border border-slate-900/50 sticky top-0 z-40 backdrop-blur-md">
          {[
            { id: 'stats', label: 'Analytics', icon: <BarChart className="w-4 h-4" /> },
            { id: 'repair', label: 'Buffer', icon: <ShieldAlert className="w-4 h-4" /> },
            { id: 'shipping', label: 'Logistics', icon: <Truck className="w-4 h-4" /> }
          ].map(btn => (
            <button key={btn.id} onClick={() => scrollToSection(btn.id as any)} className="flex-1 flex items-center justify-center gap-2 py-3.5 rounded-xl text-slate-500 hover:text-white hover:bg-white/5 transition-all text-[10px] font-black uppercase tracking-widest">
              {btn.icon} {btn.label}
            </button>
          ))}
        </div>

        {/* SCROLLABLE MAIN CONTENT */}
        <div className="flex-1 overflow-y-auto custom-scrollbar px-6 pb-12 space-y-12 pt-6">

          {/* SECTION: ANALYTICS WITH HORIZONTAL CAROUSEL */}
          <section ref={sectionRefs.stats} className="space-y-6">
            <header className="flex items-center justify-between px-2">
              <h3 className="text-[10px] font-black text-slate-600 uppercase tracking-[0.3em] flex items-center gap-3">
                <LayoutGrid className="w-4 h-4 text-indigo-500" /> Operational Insights
              </h3>
              <div className="flex gap-2">
                 <button onClick={() => scrollAnalytics('left')} className="p-1.5 bg-slate-900 border border-slate-800 rounded-lg text-slate-500 hover:text-white transition-colors"><ChevronLeft className="w-4 h-4" /></button>
                 <button onClick={() => scrollAnalytics('right')} className="p-1.5 bg-slate-900 border border-slate-800 rounded-lg text-slate-500 hover:text-white transition-colors"><ChevronRight className="w-4 h-4" /></button>
              </div>
            </header>

            {/* HORIZONTAL ANALYTICS CAROUSEL */}
            <div ref={analyticsScrollRef} className="flex overflow-x-auto gap-4 snap-x no-scrollbar pb-2">
              {/* CARD 1: QUALITY */}
              <div className="min-w-[280px] snap-center p-6 bg-gradient-to-br from-slate-900 to-slate-950 border border-white/5 rounded-[2.5rem] shadow-2xl space-y-6">
                <div className="flex justify-between items-start">
                  <div className="p-2.5 bg-emerald-500/10 rounded-2xl"><ActivitySquare className="w-5 h-5 text-emerald-500" /></div>
                  <span className="text-[9px] font-black text-emerald-500 bg-emerald-500/10 px-2 py-1 rounded">QUALITY_FTT</span>
                </div>
                <div>
                   <div className="text-4xl font-black text-white tracking-tighter tabular-nums">{((stats.passedFirstTime / (stats.produced || 1)) * 100).toFixed(1)}%</div>
                   <p className="text-[10px] font-bold text-slate-500 uppercase mt-1">Direct Pass Rate</p>
                </div>
                <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                   <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${(stats.passedFirstTime / (stats.produced || 1)) * 100}%` }} />
                </div>
              </div>

              {/* CARD 2: EFFICIENCY */}
              <div className="min-w-[280px] snap-center p-6 bg-gradient-to-br from-slate-900 to-slate-950 border border-white/5 rounded-[2.5rem] shadow-2xl space-y-6">
                <div className="flex justify-between items-start">
                  <div className="p-2.5 bg-indigo-500/10 rounded-2xl"><Timer className="w-5 h-5 text-indigo-500" /></div>
                  <span className="text-[9px] font-black text-indigo-500 bg-indigo-500/10 px-2 py-1 rounded">EFFICIENCY</span>
                </div>
                <div className="flex gap-4 items-end">
                   <div>
                     <div className="text-3xl font-black text-white tracking-tighter tabular-nums">{stats.currentTakt}s</div>
                     <p className="text-[9px] font-bold text-slate-600 uppercase mt-1">Real Takt</p>
                   </div>
                   <div className="text-slate-800 text-2xl font-black mb-1">/</div>
                   <div>
                     <div className="text-xl font-black text-slate-500 tracking-tighter tabular-nums">{stats.targetTakt}s</div>
                     <p className="text-[9px] font-bold text-slate-600 uppercase mt-1">Goal</p>
                   </div>
                </div>
                <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500 uppercase">
                   <Gauge className="w-4 h-4 text-indigo-400" /> Syncing @ 100%
                </div>
              </div>

              {/* CARD 3: REPAIR FTR */}
              <div className="min-w-[280px] snap-center p-6 bg-gradient-to-br from-slate-900 to-slate-950 border border-white/5 rounded-[2.5rem] shadow-2xl space-y-6">
                <div className="flex justify-between items-start">
                  <div className="p-2.5 bg-amber-500/10 rounded-2xl"><Wrench className="w-5 h-5 text-amber-500" /></div>
                  <span className="text-[9px] font-black text-amber-500 bg-amber-500/10 px-2 py-1 rounded">REPAIR_FTR</span>
                </div>
                <div>
                   <div className="text-4xl font-black text-white tracking-tighter tabular-nums">{((stats.ftrSuccesses / (stats.repairCompletedCount || 1)) * 100).toFixed(1)}%</div>
                   <p className="text-[10px] font-bold text-slate-500 uppercase mt-1">First Time Repair</p>
                </div>
