               {isRunning ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />} {isRunning ? 'Hold Line' : 'Engage'}
            </button>
            <button onClick={() => { vehiclesRef.current = []; setStats(s => ({...s, produced:0, totalStarted:0, defects:0, passedFirstTime:0, ftrSuccesses:0, repairCompletedCount:0})); addLog("GLOBAL_PURGE: OK"); }} className="py-4 bg-slate-900/50 border border-white/5 text-slate-600 hover:text-rose-500 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all">
